const FEATURES = [
    // ── SETUP & INIT (1–14) ─────────────────────────────────────────────
    { id: 1, cat: "Setup & Init", title: "Install CDA SDK", tip: "Use the official SDK — handles auth, retries, normalisation, and TypeScript types automatically.", code: `npm install contentful\n# Write access:\nnpm install contentful-management` },
    { id: 2, cat: "Setup & Init", title: "Initialise CDA client", tip: "Store credentials in env vars — never hardcode tokens in source code.", code: `import { createClient } from 'contentful';\n\nconst client = createClient({\n  space:       process.env.CONTENTFUL_SPACE_ID,\n  accessToken: process.env.CONTENTFUL_ACCESS_TOKEN,\n});` },
    { id: 3, cat: "Setup & Init", title: "Initialise CMA client", tip: "CMA token has write access — never expose it in client-side code.", code: `import contentfulManagement from 'contentful-management';\n\nconst cma = contentfulManagement.createClient({\n  accessToken: process.env.CONTENTFUL_MANAGEMENT_TOKEN,\n});\nconst space = await cma.getSpace(SPACE_ID);\nconst env   = await space.getEnvironment('master');` },
    { id: 4, cat: "Setup & Init", title: "Preview API client", tip: "Preview API returns unpublished entries — use only server-side, never in client bundles.", code: `const previewClient = createClient({\n  space:       process.env.CONTENTFUL_SPACE_ID,\n  accessToken: process.env.CONTENTFUL_PREVIEW_TOKEN,\n  host:        'preview.contentful.com', // <-- key difference\n});` },
    { id: 5, cat: "Setup & Init", title: "Multiple environments", tip: "Use staging/dev environments for schema changes — never test migrations on master.", code: `const client = createClient({\n  space:       SPACE_ID,\n  accessToken: ACCESS_TOKEN,\n  environment: process.env.NODE_ENV === 'production'\n    ? 'master'\n    : 'staging',\n});` },
    { id: 6, cat: "Setup & Init", title: "Retry & timeout config", tip: "The SDK retries rate-limited (429) requests automatically. Set a generous timeout for slow networks.", code: `const client = createClient({\n  space:        SPACE_ID,\n  accessToken:  ACCESS_TOKEN,\n  retryOnError: true,  // default: true\n  retryLimit:   5,     // default: 5\n  timeout:      30000, // ms\n});` },
    { id: 7, cat: "Setup & Init", title: ".env variables", tip: "Keep all four tokens: CDA, Preview, CMA, and Space ID. Validate them at startup.", code: `# .env.local\nCONTENTFUL_SPACE_ID=abc123\nCONTENTFUL_ACCESS_TOKEN=cda_xxxxx\nCONTENTFUL_PREVIEW_TOKEN=preview_xxxxx\nCONTENTFUL_MANAGEMENT_TOKEN=CFPAT-xxxxx\nCONTENTFUL_ENVIRONMENT=master` },
    { id: 8, cat: "Setup & Init", title: "Validate env at startup", tip: "Fail loudly at startup — better than a cryptic runtime error deep in a request.", code: `function requireEnv(key) {\n  const val = process.env[key];\n  if (!val) throw new Error(\`Missing env var: \${key}\`);\n  return val;\n}\n\nconst SPACE_ID     = requireEnv('CONTENTFUL_SPACE_ID');\nconst ACCESS_TOKEN = requireEnv('CONTENTFUL_ACCESS_TOKEN');` },
    { id: 9, cat: "Setup & Init", title: "Client singleton pattern", tip: "Create the client once and reuse — avoids creating multiple HTTP connection pools.", code: `// lib/contentful.ts\nimport { createClient } from 'contentful';\n\nexport const client = createClient({\n  space:       process.env.CONTENTFUL_SPACE_ID!,\n  accessToken: process.env.CONTENTFUL_ACCESS_TOKEN!,\n});\n\nexport const previewClient = createClient({\n  space:       process.env.CONTENTFUL_SPACE_ID!,\n  accessToken: process.env.CONTENTFUL_PREVIEW_TOKEN!,\n  host:        'preview.contentful.com',\n});` },
    { id: 10, cat: "Setup & Init", title: "Select client by mode", tip: "Pass a single helper to data fetchers — they get the right client (preview vs live) automatically.", code: `export function getClient(preview = false) {\n  return preview ? previewClient : client;\n}\n\n// In page fetchers:\nconst { isEnabled } = await draftMode();\nconst data = await fetchPost(slug, isEnabled);` },
    { id: 11, cat: "Setup & Init", title: "Custom fetch adapter", tip: "Override the adapter to add global logging, custom headers, or mock responses in tests.", code: `import { createClient } from 'contentful';\n\nconst client = createClient({\n  space:       SPACE_ID,\n  accessToken: ACCESS_TOKEN,\n  adapter: async (config) => {\n    console.log('CTF request:', config.url);\n    return fetch(config.url, config);\n  },\n});` },
    { id: 12, cat: "Setup & Init", title: "SDK response format", tip: "Every entry has sys (metadata) and fields (your content). Always access fields for content.", code: `const entry = await client.getEntry('ID');\n\n// Metadata:\nentry.sys.id          // entry ID\nentry.sys.updatedAt   // ISO timestamp\nentry.sys.contentType.sys.id  // content type ID\n\n// Content:\nentry.fields.title    // your field\nentry.fields.slug` },
    { id: 13, cat: "Setup & Init", title: "SDK version & changelog", tip: "Pin the SDK version in production. Check the changelog before major upgrades — breaking changes happen.", code: `# Check current version:\nnpm list contentful\n\n# Changelog:\n# https://github.com/contentful/contentful.js/releases\n\n# Pin in package.json:\n\"contentful\": \"10.x.x\"` },
    { id: 14, cat: "Setup & Init", title: "Content type IDs", tip: "Content type IDs are set when you create the type — they cannot be changed later. Use camelCase.", code: `// Content type IDs are case-sensitive\n// Set once in Contentful dashboard, cannot be renamed\n// Convention: camelCase\n//   ✅ 'blogPost', 'productPage', 'author'\n//   ❌ 'Blog Post', 'blog-post', 'BlogPost'\n\nclient.getEntries({ content_type: 'blogPost' });` },

    // ── CONTENT DELIVERY API (15–34) ───────────────────────────────────
    { id: 15, cat: "Content Delivery API", title: "Get single entry", tip: "Always destructure fields — raw entries also carry sys and metadata you usually don't need to render.", code: `const entry = await client.getEntry('ENTRY_ID');\n\nconst { title, slug, body } = entry.fields;\n// entry.sys.id, entry.sys.updatedAt, etc.` },
    { id: 16, cat: "Content Delivery API", title: "Get entries by content type", tip: "Always pass content_type — omitting it scans every type in your space (much slower).", code: `const res = await client.getEntries({\n  content_type: 'blogPost',\n  limit: 10,\n});\n\nres.items.forEach(e => console.log(e.fields.title));\nconsole.log('Total:', res.total);` },
    { id: 17, cat: "Content Delivery API", title: "Pagination", tip: "Max limit is 1000 per request. Use skip+limit loops for full collection fetches.", code: `async function getAllEntries(contentType) {\n  const all = [];\n  let skip = 0;\n  const limit = 100;\n  while (true) {\n    const res = await client.getEntries({\n      content_type: contentType, skip, limit,\n    });\n    all.push(...res.items);\n    skip += limit;\n    if (skip >= res.total) break;\n  }\n  return all;\n}` },
    { id: 18, cat: "Content Delivery API", title: "Select specific fields", tip: "Always use select in list views — removing 10 fields from 1000 entries = massive payload reduction.", code: `const res = await client.getEntries({\n  content_type: 'blogPost',\n  select: [\n    'sys.id',\n    'fields.title',\n    'fields.slug',\n    'fields.publishDate',\n    'fields.coverImage',\n  ],\n});` },
    { id: 19, cat: "Content Delivery API", title: "Include linked entries", tip: "include depth resolves linked entries inline. Default is 1, max is 10. Deeper = larger payload.", code: `const res = await client.getEntries({\n  content_type: 'blogPost',\n  include: 2, // resolve 2 levels deep\n});\n\n// Level 1 resolved automatically:\nres.items[0].fields.author.fields.name\n// Level 2:\nres.items[0].fields.author.fields.company.fields.name` },
    { id: 20, cat: "Content Delivery API", title: "Order results", tip: "Prefix with - for descending. sys.createdAt is the most reliable for chronological ordering.", code: `const res = await client.getEntries({\n  content_type: 'article',\n  order: '-sys.createdAt',      // newest first\n  // order: 'fields.publishDate'\n  // order: '-fields.views,sys.id' // multi-sort\n});` },
    { id: 21, cat: "Content Delivery API", title: "Get asset", tip: "Asset URLs have no protocol — always prepend https: before using in img src.", code: `const asset = await client.getAsset('ASSET_ID');\n\nconst url    = 'https:' + asset.fields.file.url;\nconst width  = asset.fields.file.details.image?.width;\nconst height = asset.fields.file.details.image?.height;\nconst type   = asset.fields.file.contentType;` },
    { id: 22, cat: "Content Delivery API", title: "Get all assets", tip: "Filter by contentType to retrieve only images, videos, PDFs, etc.", code: `const res = await client.getAssets({\n  'fields.file.contentType[match]': 'image/',\n  limit: 50,\n});\n\nres.items.forEach(a => {\n  console.log('https:' + a.fields.file.url);\n});` },
    { id: 23, cat: "Content Delivery API", title: "withAllLocales flag", tip: "Returns all locales in one call — fields become objects keyed by locale code.", code: `const res = await client.withAllLocales.getEntries({\n  content_type: 'page',\n});\n\nconst enTitle = res.items[0].fields.title['en-US'];\nconst deTitle = res.items[0].fields.title['de'];` },
    { id: 24, cat: "Content Delivery API", title: "withoutUnresolvableLinks", tip: "Strips broken links silently instead of throwing — safer when linked entries may be unpublished.", code: `const res = await client\n  .withoutUnresolvableLinks\n  .getEntries({\n    content_type: 'page',\n    include: 2,\n  });\n// Missing linked entries removed, not null/error` },
    { id: 25, cat: "Content Delivery API", title: "Stop reason / stop_reason", tip: "Check stop_reason to detect if a response was paginated or complete.", code: `// Responses include:\n// res.total   — total matching entries\n// res.skip    — current offset\n// res.limit   — page size\n// res.items   — current page\n\nconst isLastPage = res.skip + res.items.length >= res.total;` },
    { id: 26, cat: "Content Delivery API", title: "Sync API — initial", tip: "Sync API gives you a token. Store it to enable incremental syncs and avoid full rebuilds.", code: `const sync = await client.sync({\n  initial:      true,\n  type:         'Entry',\n  content_type: 'blogPost', // optional scope\n});\n\nconst { entries, deletedEntries, nextSyncToken } = sync;\nawait saveToken(nextSyncToken); // persist this!` },
    { id: 27, cat: "Content Delivery API", title: "Sync API — incremental", tip: "Only fetches entries changed since the last sync — drastically cuts build times on large spaces.", code: `const storedToken = await loadToken();\n\nconst sync = await client.sync({\n  nextSyncToken: storedToken,\n});\n\n// Only what changed since last sync:\nsync.entries        // created or updated\nsync.deletedEntries // deleted\nawait saveToken(sync.nextSyncToken);` },
    { id: 28, cat: "Content Delivery API", title: "Count-only query", tip: "Use limit: 0 to get total count without fetching any entry data — very cheap.", code: `const res = await client.getEntries({\n  content_type: 'blogPost',\n  'fields.category.sys.id': 'CAT_ID',\n  limit: 0, // fetch nothing, just total\n});\n\nconsole.log('Total:', res.total);` },
    { id: 29, cat: "Content Delivery API", title: "Locale parameter", tip: "Always pass locale explicitly — relying on defaults causes subtle locale mismatch bugs.", code: `const res = await client.getEntries({\n  content_type: 'page',\n  locale: 'de', // 'en-US', 'fr', 'de', etc.\n});\n\n// Single entry with locale:\nconst entry = await client.getEntry('ID', { locale: 'de' });` },
    { id: 30, cat: "Content Delivery API", title: "Entries by IDs (bulk)", tip: "Fetch multiple known IDs in one request — avoids N+1 patterns.", code: `const res = await client.getEntries({\n  'sys.id[in]': ['id1', 'id2', 'id3'].join(','),\n});\n\n// Returns up to the matched entries\n// Note: preserves no order guarantee` },
    { id: 31, cat: "Content Delivery API", title: "Chaining query helpers", tip: "Build typed helpers for common queries — reduces duplication and makes fetchers readable.", code: `const ctf = {\n  posts:   (p = {}) => client.getEntries({ content_type: 'blogPost',   include: 1, ...p }),\n  pages:   (p = {}) => client.getEntries({ content_type: 'page',       include: 2, ...p }),\n  authors: (p = {}) => client.getEntries({ content_type: 'author',     ...p }),\n};\n\nconst { items } = await ctf.posts({ limit: 5, 'fields.featured': true });` },
    { id: 32, cat: "Content Delivery API", title: "Throttle polling", tip: "Never poll CDA on every request — use cache + webhooks + ISR instead.", code: `// ❌ Calls Contentful on every request:\nexport async function GET() {\n  return Response.json(await client.getEntries(...));\n}\n\n// ✅ Cache-first:\nconst getCached = unstable_cache(\n  () => client.getEntries({ content_type: 'config' }),\n  ['config'],\n  { revalidate: 300 }\n);` },
    { id: 33, cat: "Content Delivery API", title: "Locale fallback chain", tip: "Contentful respects locale fallback chains you configure in the dashboard — SDK honours them automatically.", code: `// Configure in Contentful: Settings > Locales > Fallback\n// e.g. pt-BR → pt → en-US\n\n// SDK fetches pt-BR, auto-falls-back through chain:\nconst entry = await client.getEntry('ID', { locale: 'pt-BR' });\n// title is pt-BR if set, else pt, else en-US` },
    { id: 34, cat: "Content Delivery API", title: "Detect archived entries", tip: "Archived entries still exist on CDA with sys.archivedAt set — exclude them explicitly.", code: `const res = await client.getEntries({\n  content_type: 'article',\n  'sys.archivedAt[exists]': false,\n  'sys.publishedAt[exists]': true,\n});` },

    // ── CONTENT MANAGEMENT API (35–50) ────────────────────────────────
    { id: 35, cat: "Content Management API", title: "Create entry", tip: "Fields must match your content type schema exactly — extra fields are rejected.", code: `const entry = await env.createEntry('blogPost', {\n  fields: {\n    title:     { 'en-US': 'My new post' },\n    slug:      { 'en-US': 'my-new-post' },\n    published: { 'en-US': false },\n  },\n});\nconsole.log('Created:', entry.sys.id);` },
    { id: 36, cat: "Content Management API", title: "Publish entry", tip: "Entries must be published to appear via CDA. Draft = invisible to public.", code: `let entry = await env.getEntry('ENTRY_ID');\nentry = await entry.publish();\n// entry.sys.publishedAt is now set` },
    { id: 37, cat: "Content Management API", title: "Unpublish entry", tip: "Unpublished entries remain in Contentful but are hidden from CDA.", code: `let entry = await env.getEntry('ENTRY_ID');\nentry = await entry.unpublish();\n// entry is now a draft again` },
    { id: 38, cat: "Content Management API", title: "Update entry fields", tip: "Always re-fetch before updating to get the latest sys.version — avoids 409 version conflicts.", code: `let entry = await env.getEntry('ENTRY_ID');\nentry.fields.title['en-US'] = 'Updated title';\nentry = await entry.update();  // saves as draft\nentry = await entry.publish(); // make it live` },
    { id: 39, cat: "Content Management API", title: "Delete entry", tip: "You cannot delete a published entry — unpublish first or you get a 422 error.", code: `let entry = await env.getEntry('ENTRY_ID');\nif (entry.sys.publishedAt) await entry.unpublish();\nawait entry.delete();` },
    { id: 40, cat: "Content Management API", title: "Upload asset", tip: "Two-step process: create asset metadata, then call processForAllLocales() to trigger the upload.", code: `let asset = await env.createAsset({\n  fields: {\n    title: { 'en-US': 'Logo' },\n    file: {\n      'en-US': {\n        contentType: 'image/png',\n        fileName:    'logo.png',\n        upload:      'https://example.com/logo.png',\n      },\n    },\n  },\n});\nasset = await asset.processForAllLocales();\nasset = await asset.publish();` },
    { id: 41, cat: "Content Management API", title: "Link entry to another", tip: "Links use sys.type Link + linkType — never store raw IDs in reference fields.", code: `entry.fields.author = {\n  'en-US': {\n    sys: {\n      type:     'Link',\n      linkType: 'Entry',\n      id:       'AUTHOR_ENTRY_ID',\n    },\n  },\n};\nawait entry.update();` },
    { id: 42, cat: "Content Management API", title: "Bulk publish", tip: "Use the bulk actions API for 200+ items — single-publish loops hit rate limits fast.", code: `const action = await env.createPublishBulkAction({\n  entities: {\n    sys:   { type: 'Array' },\n    items: entryIds.map(id => ({\n      sys: { type: 'Link', linkType: 'Entry', id },\n    })),\n  },\n});\nawait action.waitProcessing();` },
    { id: 43, cat: "Content Management API", title: "Bulk unpublish", tip: "Bulk unpublish is much faster than looping unpublish() calls one by one.", code: `const action = await env.createUnpublishBulkAction({\n  entities: {\n    sys:   { type: 'Array' },\n    items: entryIds.map(id => ({\n      sys: { type: 'Link', linkType: 'Entry', id },\n    })),\n  },\n});\nawait action.waitProcessing();` },
    { id: 44, cat: "Content Management API", title: "Scheduled publishing", tip: "Use Scheduled Actions to publish/unpublish entries at a specific future time.", code: `await env.createScheduledAction({\n  entity: { sys: { type: 'Link', linkType: 'Entry', id: 'ENTRY_ID' } },\n  environment: { sys: { type: 'Link', linkType: 'Environment', id: 'master' } },\n  action:      'publish',\n  scheduledFor: { datetime: '2025-01-01T00:00:00Z' },\n});` },
    { id: 45, cat: "Content Management API", title: "Read version history", tip: "Snapshots preserve full entry state — useful for audit trails and manual rollback.", code: `const snapshots = await env.getEntrySnapshots('ENTRY_ID', { limit: 10 });\n\nsnapshots.items.forEach(snap => {\n  console.log(\n    snap.sys.createdAt,\n    snap.snapshot.sys.version,\n    snap.snapshot.fields.title?.['en-US'],\n  );\n});` },
    { id: 46, cat: "Content Management API", title: "Content type CRUD", tip: "Always call update() then publish() after editing a content type definition.", code: `const ct = await env.getContentType('blogPost');\nct.fields.push({\n  id: 'readingTime', name: 'Reading time', type: 'Integer',\n});\nawait ct.update();\nawait ct.publish();` },
    { id: 47, cat: "Content Management API", title: "Patch entry (REST)", tip: "The SDK has no PATCH — use the CMA REST endpoint with JSON Patch for partial updates.", code: `await fetch(\n  \`https://api.contentful.com/spaces/\${SPACE}/environments/master/entries/\${ID}\`,\n  {\n    method: 'PATCH',\n    headers: {\n      Authorization: \`Bearer \${CMA_TOKEN}\`,\n      'Content-Type': 'application/json-patch+json',\n      'X-Contentful-Version': entry.sys.version,\n    },\n    body: JSON.stringify([\n      { op: 'replace', path: '/fields/title/en-US', value: 'New title' }\n    ]),\n  }\n);` },
    { id: 48, cat: "Content Management API", title: "Tag management", tip: "Metadata tags are space-level — create once, reuse across all entry types.", code: `// Create tag:\nawait env.createTag('featured', 'Featured');\n\n// Get all tags:\nconst tags = await env.getTags();\n\n// Add tag to entry:\nentry.metadata.tags.push({\n  sys: { type: 'Link', linkType: 'Tag', id: 'featured' },\n});\nawait entry.update();` },
    { id: 49, cat: "Content Management API", title: "Editorial tasks", tip: "Tasks are Contentful's built-in workflow mechanism — assign review tasks to team members.", code: `const task = await entry.createTask({\n  body: 'Please review SEO metadata',\n  assignedTo: {\n    sys: { type: 'Link', linkType: 'User', id: USER_ID },\n  },\n  status: 'active',\n});` },
    { id: 50, cat: "Content Management API", title: "Search & replace via CMA", tip: "Bulk update field values across all entries — useful for domain changes or copy updates.", code: `const entries = await env.getEntries({ content_type: 'article', limit: 1000 });\n\nfor (const entry of entries.items) {\n  const body = entry.fields.body?.['en-US'] ?? '';\n  if (body.includes('old-domain.com')) {\n    entry.fields.body['en-US'] = body.replaceAll('old-domain.com', 'new-domain.com');\n    await entry.update();\n    await entry.publish();\n  }\n}` },

    // ── GRAPHQL API (51–64) ────────────────────────────────────────────
    { id: 51, cat: "GraphQL API", title: "GraphQL endpoint", tip: "Use GraphQL when you need precise field selection across nested types — avoids over-fetching.", code: `const ENDPOINT = \`https://graphql.contentful.com/content/v1/spaces/\${SPACE_ID}\`;\n\nconst res = await fetch(ENDPOINT, {\n  method: 'POST',\n  headers: {\n    'Content-Type':  'application/json',\n    'Authorization': \`Bearer \${ACCESS_TOKEN}\`,\n  },\n  body: JSON.stringify({ query }),\n});` },
    { id: 52, cat: "GraphQL API", title: "Basic collection query", tip: "Collection queries return items array + total. Always request sys.id for React key props.", code: `query {\n  blogPostCollection(limit: 10, order: sys_firstPublishedAt_DESC) {\n    total\n    items {\n      sys { id }\n      title\n      slug\n      publishDate\n    }\n  }\n}` },
    { id: 53, cat: "GraphQL API", title: "Query with variables", tip: "Always use variables — never string-interpolate user input into GraphQL queries.", code: `const query = \`\n  query GetPost($slug: String!) {\n    blogPostCollection(where: { slug: $slug }, limit: 1) {\n      items {\n        title\n        body { json }\n        author { name }\n      }\n    }\n  }\n\`;\n\nfetch(ENDPOINT, {\n  method: 'POST',\n  headers: { Authorization: \`Bearer \${TOKEN}\`, 'Content-Type': 'application/json' },\n  body: JSON.stringify({ query, variables: { slug: 'my-post' } }),\n});` },
    { id: 54, cat: "GraphQL API", title: "Nested linked entries", tip: "GraphQL lets you define exact nested fields — no more guessing include depth.", code: `query {\n  articleCollection {\n    items {\n      title\n      author {\n        name\n        avatar { url }\n      }\n      tagsCollection {\n        items { name slug }\n      }\n    }\n  }\n}` },
    { id: 55, cat: "GraphQL API", title: "Preview via GraphQL", tip: "Add preview: true to query unpublished draft entries from GraphQL.", code: `query {\n  blogPostCollection(preview: true, limit: 5) {\n    items {\n      sys { id }\n      title\n      # draft/unpublished content included\n    }\n  }\n}` },
    { id: 56, cat: "GraphQL API", title: "Where filter syntax", tip: "GraphQL filters are strongly typed — they map 1:1 with CDA operators.", code: `query {\n  blogPostCollection(where: {\n    title_contains:    \"React\"\n    publishDate_gte:   \"2024-01-01\"\n    featured:          true\n    category: { slug: \"engineering\" }\n  }) {\n    items { title }\n  }\n}` },
    { id: 57, cat: "GraphQL API", title: "__typename for polymorphism", tip: "Use __typename to switch renderer components for union-type sections fields.", code: `query {\n  pageCollection {\n    items {\n      sectionsCollection {\n        items {\n          __typename\n          ... on Hero        { headline cta }\n          ... on FeatureGrid { title }\n          ... on Testimonials { quotes { author text } }\n        }\n      }\n    }\n  }\n}` },
    { id: 58, cat: "GraphQL API", title: "Fragments", tip: "Use fragments to share field selections across queries — keeps queries DRY.", code: `fragment PostFields on BlogPost {\n  sys { id }\n  title\n  slug\n  coverImage { url width height }\n}\n\nquery {\n  blogPostCollection(limit: 20) {\n    items { ...PostFields }\n  }\n}` },
    { id: 59, cat: "GraphQL API", title: "Pagination in GraphQL", tip: "Contentful GraphQL uses skip+limit pagination — not cursor-based.", code: `query GetPosts($skip: Int!) {\n  blogPostCollection(limit: 10, skip: $skip) {\n    total\n    items { title slug }\n  }\n}\n\n// Loop:\nlet skip = 0;\nwhile (true) {\n  const { data } = await gql(GET_POSTS, { skip });\n  const { items, total } = data.blogPostCollection;\n  all.push(...items);\n  skip += 10;\n  if (skip >= total) break;\n}` },
    { id: 60, cat: "GraphQL API", title: "sys fields in GraphQL", tip: "sys.id, publishedAt, and firstPublishedAt are frequently needed — always include sys.", code: `query {\n  blogPostCollection {\n    items {\n      sys {\n        id\n        publishedAt\n        firstPublishedAt\n      }\n      title\n    }\n  }\n}` },
    { id: 61, cat: "GraphQL API", title: "Apollo Client setup", tip: "Apollo's normalised cache + automatic refetching pairs well with Contentful GraphQL.", code: `import { ApolloClient, InMemoryCache, createHttpLink } from '@apollo/client';\n\nexport const apolloClient = new ApolloClient({\n  link: createHttpLink({\n    uri:     \`https://graphql.contentful.com/content/v1/spaces/\${SPACE_ID}\`,\n    headers: { Authorization: \`Bearer \${ACCESS_TOKEN}\` },\n  }),\n  cache: new InMemoryCache(),\n  defaultOptions: { query: { fetchPolicy: 'cache-first' } },\n});` },
    { id: 62, cat: "GraphQL API", title: "Asset collection query", tip: "Query assets via GraphQL for fully typed access to file metadata and dimensions.", code: `query {\n  assetCollection(\n    where: { contentType: \"image/png\" },\n    limit: 20\n  ) {\n    items {\n      sys { id }\n      title\n      url\n      width\n      height\n      size\n    }\n  }\n}` },
    { id: 63, cat: "GraphQL API", title: "GraphQL playground", tip: "Use the interactive playground to explore your schema and build queries before adding them to code.", code: `# Open in browser:\nhttps://graphql.contentful.com/content/v1/spaces/{SPACE_ID}/explore\n  ?access_token={CDA_TOKEN}\n\n# Supports:\n# - Schema introspection\n# - Autocomplete\n# - Query history\n# - Variable editor` },
    { id: 64, cat: "GraphQL API", title: "Persisted queries", tip: "Persist frequently-used queries server-side to reduce bandwidth and enable CDN caching.", code: `# Enable via: Apps > Manage apps > GraphQL Persisted Queries\n# Then execute by hash:\nconst res = await fetch(\n  \`https://graphql.contentful.com/content/v1/spaces/\${SPACE}/persisted\`,\n  {\n    method: 'POST',\n    headers: { Authorization: \`Bearer \${TOKEN}\` },\n    body: JSON.stringify({\n      id: 'QUERY_HASH',\n      variables: { slug: 'home' },\n    }),\n  }\n);` },

    // ── RICH TEXT (65–78) ──────────────────────────────────────────────
    { id: 65, cat: "Rich Text", title: "Install renderer", tip: "Never parse rich text JSON manually — always use the official renderer.", code: `npm install @contentful/rich-text-react-renderer\nnpm install @contentful/rich-text-types` },
    { id: 66, cat: "Rich Text", title: "Basic render", tip: "documentToReactComponents handles all standard node types out of the box.", code: `import { documentToReactComponents } from '@contentful/rich-text-react-renderer';\n\nfunction RichText({ document }) {\n  return <div>{documentToReactComponents(document)}</div>;\n}` },
    { id: 67, cat: "Rich Text", title: "Custom node renderers", tip: "Always define custom renderers for embedded entries and assets — defaults are bare wrappers.", code: `import { BLOCKS, INLINES } from '@contentful/rich-text-types';\n\nconst options = {\n  renderNode: {\n    [BLOCKS.HEADING_1]: (node, children) => <h1 className=\"text-4xl\">{children}</h1>,\n    [BLOCKS.PARAGRAPH]:  (node, children) => <p className=\"mb-4\">{children}</p>,\n    [BLOCKS.EMBEDDED_ENTRY]: (node) => {\n      const entry = node.data.target;\n      return <CalloutBox {...entry.fields} />;\n    },\n    [INLINES.HYPERLINK]: (node, children) => (\n      <a href={node.data.uri} className=\"text-blue-600\">{children}</a>\n    ),\n  },\n};\n\ndocumentToReactComponents(richTextField, options)` },
    { id: 68, cat: "Rich Text", title: "Embedded asset renderer", tip: "Always add width + height to avoid layout shift — both are in file.details.image.", code: `[BLOCKS.EMBEDDED_ASSET]: (node) => {\n  const { file, title } = node.data.target.fields;\n  return (\n    <img\n      src={'https:' + file.url}\n      alt={title}\n      width={file.details.image.width}\n      height={file.details.image.height}\n      className=\"rounded-lg my-6\"\n    />\n  );\n},` },
    { id: 69, cat: "Rich Text", title: "Custom marks", tip: "Custom mark renderers let you apply your design system's typography to bold/italic/code.", code: `import { MARKS } from '@contentful/rich-text-types';\n\nconst options = {\n  renderMark: {\n    [MARKS.BOLD]:      text => <strong className=\"font-semibold\">{text}</strong>,\n    [MARKS.ITALIC]:    text => <em>{text}</em>,\n    [MARKS.CODE]:      text => <code className=\"font-mono bg-gray-100 px-1\">{text}</code>,\n    [MARKS.UNDERLINE]: text => <u>{text}</u>,\n  },\n};` },
    { id: 70, cat: "Rich Text", title: "Rich text in GraphQL", tip: "GraphQL returns rich text as { json, links }. Pass links to your renderer for embedded entry resolution.", code: `query {\n  blogPostCollection {\n    items {\n      body {\n        json\n        links {\n          entries {\n            block  { sys { id } ... on Callout { title } }\n          }\n          assets {\n            block  { sys { id } url width height }\n          }\n        }\n      }\n    }\n  }\n}` },
    { id: 71, cat: "Rich Text", title: "Resolve embedded from GraphQL", tip: "Build a lookup map from links.entries.block for O(1) resolution in custom renderers.", code: `function buildEntryMap(links) {\n  const map = {};\n  links?.entries?.block?.forEach(e => { map[e.sys.id] = e; });\n  links?.assets?.block?.forEach(a => { map[a.sys.id] = a; });\n  return map;\n}\n\nconst entryMap = buildEntryMap(body.links);\nconst opts = {\n  renderNode: {\n    [BLOCKS.EMBEDDED_ENTRY]: (node) => {\n      const entry = entryMap[node.data.target.sys.id];\n      return <DynamicBlock entry={entry} />;\n    },\n  },\n};\ndocumentToReactComponents(body.json, opts)` },
    { id: 72, cat: "Rich Text", title: "Plain text extract", tip: "Use the plain text renderer for meta descriptions, OG tags, and word counts.", code: `import { documentToPlainTextString } from '@contentful/rich-text-plain-text-renderer';\n\nconst plainText = documentToPlainTextString(entry.fields.body);\nconst excerpt   = plainText.slice(0, 160);\nconst wordCount = plainText.split(/\s+/).length;` },
    { id: 73, cat: "Rich Text", title: "Tables in rich text", tip: "Rich text tables are supported since 2022 — requires @contentful/rich-text-types ≥14.", code: `import { BLOCKS } from '@contentful/rich-text-types';\n// BLOCKS.TABLE, TABLE_ROW, TABLE_CELL, TABLE_HEADER_CELL\n\nconst options = {\n  renderNode: {\n    [BLOCKS.TABLE]:             (n, c) => <table className=\"border\">{c}</table>,\n    [BLOCKS.TABLE_ROW]:         (n, c) => <tr>{c}</tr>,\n    [BLOCKS.TABLE_CELL]:        (n, c) => <td className=\"p-2 border\">{c}</td>,\n    [BLOCKS.TABLE_HEADER_CELL]: (n, c) => <th className=\"p-2 font-bold border\">{c}</th>,\n  },\n};` },
    { id: 74, cat: "Rich Text", title: "Table of contents generator", tip: "Walk rich text JSON to extract headings — no DOM parsing needed.", code: `function extractHeadings(document) {\n  return document.content\n    .filter(n => ['heading-2','heading-3'].includes(n.nodeType))\n    .map(n => ({\n      level: n.nodeType === 'heading-2' ? 2 : 3,\n      text:  n.content[0]?.value ?? '',\n      id:    (n.content[0]?.value ?? '')\n               .toLowerCase().replace(/\\s+/g, '-'),\n    }));\n}` },
    { id: 75, cat: "Rich Text", title: "Anchor links from headings", tip: "Generate anchor IDs from heading text for table-of-contents deep linking.", code: `const toSlug = (text) =>\n  text.toLowerCase().replace(/\\s+/g, '-').replace(/[^a-z0-9-]/g, '');\n\n[BLOCKS.HEADING_2]: (node, children) => {\n  const text = node.content[0]?.value ?? '';\n  return <h2 id={toSlug(text)}>{children}</h2>;\n},` },
    { id: 76, cat: "Rich Text", title: "Code blocks with syntax highlight", tip: "Wrap code blocks in a custom renderer with react-syntax-highlighter.", code: `import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';\n\n[BLOCKS.CODE]: (node) => {\n  const code = node.content[0]?.value ?? '';\n  const lang  = node.data?.language ?? 'text';\n  return (\n    <SyntaxHighlighter language={lang}>\n      {code}\n    </SyntaxHighlighter>\n  );\n}` },
    { id: 77, cat: "Rich Text", title: "Footnotes via embedded entries", tip: "Use an embedded inline entry type 'Footnote' to store footnote text inline.", code: `[INLINES.EMBEDDED_ENTRY]: (node) => {\n  const entry = node.data.target;\n  if (entry.sys.contentType.sys.id === 'footnote') {\n    return (\n      <sup title={entry.fields.text}>\n        [<a href={\`#fn-\${entry.sys.id}\`}>{entry.fields.number}</a>]\n      </sup>\n    );\n  }\n  return null;\n}` },
    { id: 78, cat: "Rich Text", title: "Rich text to HTML string", tip: "Use the HTML renderer for email templates, RSS feeds, and server-side rendering without React.", code: `import { documentToHtmlString } from '@contentful/rich-text-html-renderer';\n\nconst html = documentToHtmlString(entry.fields.body, {\n  renderNode: {\n    [BLOCKS.PARAGRAPH]: (node, next) =>\n      \`<p class=\"mb-4\">\${next(node.content)}</p>\`,\n  },\n});` },

    // ── ASSETS & MEDIA (79–90) ────────────────────────────────────────
    { id: 79, cat: "Assets & Media", title: "Image transformation API", tip: "Contentful Images API resizes/crops/converts on-the-fly — no separate CDN needed.", code: `const base = 'https://images.ctfassets.net/{space}/{file}';\n\n// Width + WebP:\nconst src = \`\${base}?w=800&fm=webp&q=80\`;\n\n// Fit modes: pad | fill | scale | crop | thumb\nconst cropped = \`\${base}?w=400&h=400&fit=fill&f=face\`;` },
    { id: 80, cat: "Assets & Media", title: "Responsive srcset", tip: "Build srcsets from a single Contentful URL — no extra storage or image duplication.", code: `function contentfulSrcSet(url, widths = [320, 640, 960, 1280, 1920]) {\n  const base = 'https:' + url;\n  return widths\n    .map(w => \`\${base}?w=\${w}&fm=webp&q=80 \${w}w\`)\n    .join(', ');\n}\n\n<img\n  src={\`https:\${url}?w=800\`}\n  srcSet={contentfulSrcSet(url)}\n  sizes=\"(max-width: 768px) 100vw, 800px\"\n  alt={title}\n/>` },
    { id: 81, cat: "Assets & Media", title: "Next/Image with Contentful", tip: "Use a custom loader to combine Next.js image optimisation with Contentful transforms.", code: `const contentfulLoader = ({ src, width, quality }) =>\n  \`https:\${src}?w=\${width}&q=\${quality ?? 80}&fm=webp\`;\n\n<Image\n  loader={contentfulLoader}\n  src={asset.fields.file.url}\n  alt={asset.fields.title}\n  width={asset.fields.file.details.image.width}\n  height={asset.fields.file.details.image.height}\n/>` },
    { id: 82, cat: "Assets & Media", title: "AVIF / WebP negotiation", tip: "AVIF is 30-50% smaller than WebP at the same quality — use picture for progressive enhancement.", code: `<picture>\n  <source srcSet={\`\${url}?fm=avif&w=800\`} type=\"image/avif\" />\n  <source srcSet={\`\${url}?fm=webp&w=800\`} type=\"image/webp\" />\n  <img src={\`\${url}?w=800\`} alt={alt} width={800} />\n</picture>` },
    { id: 83, cat: "Assets & Media", title: "Focal-point crop", tip: "Use f= to control crop focal point — face detection finds faces automatically.", code: `// f= options: center | top | right | left | bottom\n//             top_right | top_left | bottom_right | bottom_left\n//             face | faces\nconst url = \`https://images.ctfassets.net/.../file.jpg\n  ?w=400&h=400&fit=fill&f=face\`;` },
    { id: 84, cat: "Assets & Media", title: "Blur placeholder", tip: "Generate a tiny base64 placeholder for images before they load — eliminates layout shift.", code: `async function getBlurPlaceholder(assetUrl) {\n  const tinyUrl = \`https:\${assetUrl}?w=10&q=20&fm=jpg\`;\n  const res = await fetch(tinyUrl);\n  const buf = await res.arrayBuffer();\n  return \`data:image/jpeg;base64,\${Buffer.from(buf).toString('base64')}\`;\n}` },
    { id: 85, cat: "Assets & Media", title: "Video assets", tip: "Contentful stores but doesn't transcode video. Use Mux or Cloudinary for HLS streaming.", code: `const video = await client.getAsset('VIDEO_ASSET_ID');\nconst src = 'https:' + video.fields.file.url;\n\n<video controls preload=\"metadata\">\n  <source src={src} type={video.fields.file.contentType} />\n</video>` },
    { id: 86, cat: "Assets & Media", title: "Audio assets", tip: "HTML5 audio element works directly with Contentful audio file URLs.", code: `function AudioPlayer({ asset }) {\n  return (\n    <audio controls preload=\"metadata\" style={{ width: '100%' }}>\n      <source\n        src={'https:' + asset.fields.file.url}\n        type={asset.fields.file.contentType}\n      />\n      Your browser does not support audio.\n    </audio>\n  );\n}` },
    { id: 87, cat: "Assets & Media", title: "PDF & file assets", tip: "Detect content type before rendering — PDFs and binaries need download links, not img tags.", code: `function AssetRenderer({ asset }) {\n  const { contentType, url, fileName } = asset.fields.file;\n  if (contentType === 'application/pdf') {\n    return <a href={'https:' + url} download={fileName}>📄 {asset.fields.title}</a>;\n  }\n  if (contentType.startsWith('image/')) {\n    return <img src={'https:' + url + '?w=800&fm=webp'} alt={asset.fields.title} />;\n  }\n  return <a href={'https:' + url}>{asset.fields.title}</a>;\n}` },
    { id: 88, cat: "Assets & Media", title: "Lazy load images", tip: "Use loading=lazy on below-fold images — no JS required, supported in all modern browsers.", code: `<img\n  src={'https:' + asset.fields.file.url + '?w=800&fm=webp'}\n  alt={asset.fields.title}\n  loading=\"lazy\"\n  decoding=\"async\"\n  width={asset.fields.file.details.image.width}\n  height={asset.fields.file.details.image.height}\n/>` },
    { id: 89, cat: "Assets & Media", title: "SVG assets", tip: "Use img tag for SVGs from Contentful — dangerouslySetInnerHTML risks XSS.", code: `const isSvg = asset.fields.file.contentType === 'image/svg+xml';\n\n// ✅ Safe:\nif (isSvg) return (\n  <img src={'https:' + asset.fields.file.url} alt={asset.fields.title} />\n);\n\n// ❌ Risky — don't do this with Contentful SVGs:\n// dangerouslySetInnerHTML={{ __html: svgText }}` },
    { id: 90, cat: "Assets & Media", title: "Dominant color placeholder", tip: "Store dominant color on your asset entry for a branded loading state.", code: `// Contentful asset custom field: dominantColor (Symbol)\n// Set via script or Contentful App when uploading\n\n<div\n  style={{\n    background: asset.fields.dominantColor ?? '#e8e5de',\n    aspectRatio: '16/9',\n  }}\n  className=\"animate-pulse rounded-lg\"\n/>` },

    // ── QUERYING & FILTERING (91–104) ─────────────────────────────────
    { id: 91, cat: "Querying & Filtering", title: "Equality filter", tip: "Fields must be marked as searchable in your content type for filtering to work.", code: `const res = await client.getEntries({\n  content_type: 'product',\n  'fields.featured': true,\n  'fields.category.sys.id': 'CATEGORY_ID',\n});` },
    { id: 92, cat: "Querying & Filtering", title: "String operators", tip: "[match] is full-text contains. [in] is exact multi-value OR. [ne] is not-equal.", code: `// Contains (case-insensitive):\n'fields.title[match]': 'contentful'\n\n// Exact multi-value (OR logic):\n'fields.status[in]': 'draft,review,published'\n\n// Not equal:\n'fields.hidden[ne]': true\n\n// Not in:\n'fields.status[nin]': 'archived,deleted'` },
    { id: 93, cat: "Querying & Filtering", title: "Range filters", tip: "Works on dates, numbers, and any comparable field type.", code: `// Date range:\n'fields.publishDate[gte]': '2024-01-01',\n'fields.publishDate[lte]': '2024-12-31',\n\n// Number range:\n'fields.price[gt]':  10,\n'fields.price[lte]': 100,` },
    { id: 94, cat: "Querying & Filtering", title: "Array / tags filter", tip: "[all] = must contain all values. [in] = must contain at least one.", code: `// Entry must have ALL these tags:\n'metadata.tags.sys.id[all]': 'featured,homepage'\n\n// Entry has ANY of these tags:\n'metadata.tags.sys.id[in]': 'news,blog,updates'` },
    { id: 95, cat: "Querying & Filtering", title: "Location / geo filter", tip: "Set field type to Location in Contentful to enable proximity and bounding-box queries.", code: `// Within radius (km) of a point:\n'fields.location[within]': '51.5074,-0.1278,10'\n// format: lat,lon,radius_km\n\n// Within a bounding box:\n'fields.location[within]': '51.4,-0.25,51.6,-0.05'` },
    { id: 96, cat: "Querying & Filtering", title: "sys filters", tip: "Filter on system metadata — useful for changed-since queries in incremental builds.", code: `// Updated after timestamp:\n'sys.updatedAt[gte]': '2024-06-01T00:00:00Z'\n\n// Specific IDs (OR):\n'sys.id[in]': 'id1,id2,id3'\n\n// By content type:\n'sys.contentType.sys.id': 'blogPost'` },
    { id: 97, cat: "Querying & Filtering", title: "Full-text search", tip: "query does a full-text search across all searchable fields — always scope with content_type.", code: `const res = await client.getEntries({\n  content_type: 'article',\n  query: 'serverless edge functions', // full-text\n});` },
    { id: 98, cat: "Querying & Filtering", title: "Exists / not-exists", tip: "[exists] true finds entries where the field is set; false finds where it is missing.", code: `// Has a value:\n'fields.featuredImage[exists]': true\n\n// Field is empty/missing:\n'fields.archivedAt[exists]': false` },
    { id: 99, cat: "Querying & Filtering", title: "Boolean filtering", tip: "Boolean fields: pass true/false as values, not strings — strings return no results.", code: `// ✅ Correct:\n'fields.featured': true\n'fields.published': false\n\n// ❌ Wrong — returns no results:\n'fields.featured': 'true'` },
    { id: 100, cat: "Querying & Filtering", title: "Filter by linked entry field", tip: "Two-level linked filtering: posts where author.country = 'AU'.", code: `const res = await client.getEntries({\n  content_type: 'article',\n  'fields.author.sys.contentType.sys.id':   'author',\n  'fields.author.fields.country[match]':    'Australia',\n  include: 1,\n});` },
    { id: 101, cat: "Querying & Filtering", title: "AND / OR query patterns", tip: "Multiple params are AND'd. For OR, use [in] operator or make separate requests.", code: `// AND: featured AND in category X:\nconst res = await client.getEntries({\n  content_type: 'blogPost',\n  'fields.featured': true,\n  'fields.category.sys.id': 'CAT_ID',\n});\n\n// OR: in category X OR Y:\nconst res = await client.getEntries({\n  content_type: 'blogPost',\n  'fields.category.sys.id[in]': 'CAT_X,CAT_Y',\n});` },
    { id: 102, cat: "Querying & Filtering", title: "Near-real-time content", tip: "Cache for 10-30s at edge for near-real-time content without rate limit risk.", code: `export async function GET() {\n  const res = await client.getEntries({\n    content_type: 'liveUpdate',\n    order: '-sys.updatedAt',\n    limit: 5,\n  });\n  return Response.json(res.items, {\n    headers: { 'Cache-Control': 's-maxage=15, stale-while-revalidate=30' },\n  });\n}` },
    { id: 103, cat: "Querying & Filtering", title: "Scheduled / future content", tip: "Query entries with a future startDate to surface 'coming soon' content.", code: `// Events not yet started:\nconst res = await previewClient.getEntries({\n  content_type: 'event',\n  'fields.startDate[gte]': new Date().toISOString(),\n  order: 'fields.startDate',\n});` },
    { id: 104, cat: "Querying & Filtering", title: "Complex nested filter", tip: "Combine multiple filter levels for powerful content-graph traversal.", code: `// Posts in a category that belongs to a specific parent:\nconst res = await client.getEntries({\n  content_type: 'blogPost',\n  'fields.category.fields.parent.sys.id': 'PARENT_CAT_ID',\n  'fields.featured': true,\n  'fields.publishDate[lte]': new Date().toISOString(),\n  include: 2,\n  order: '-fields.publishDate',\n});` },

    // ── LOCALIZATION (105–114) ─────────────────────────────────────────
    { id: 105, cat: "Localization", title: "Locale parameter", tip: "Always pass locale explicitly — relying on defaults causes subtle bugs.", code: `const res = await client.getEntries({\n  content_type: 'page',\n  locale: 'de',\n});\n\nconst entry = await client.getEntry('ID', { locale: 'de' });` },
    { id: 106, cat: "Localization", title: "withAllLocales", tip: "withAllLocales avoids N requests for N locales — perfect for static site generation.", code: `const res = await client.withAllLocales.getEntries({\n  content_type: 'page',\n});\n\nconst enTitle = res.items[0].fields.title['en-US'];\nconst deTitle = res.items[0].fields.title['de'];` },
    { id: 107, cat: "Localization", title: "Build paths for all locales", tip: "Combine withAllLocales + getStaticPaths for full multilingual SSG with one query.", code: `export async function getStaticPaths() {\n  const res = await client.withAllLocales.getEntries({ content_type: 'page' });\n  const locales = ['en-US', 'de', 'fr'];\n  const paths = res.items.flatMap(item =>\n    locales.map(locale => ({\n      params: { slug: item.fields.slug[locale] ?? item.fields.slug['en-US'] },\n      locale,\n    }))\n  );\n  return { paths, fallback: false };\n}` },
    { id: 108, cat: "Localization", title: "Locale fallback chain", tip: "Configure fallbacks in Contentful dashboard — SDK respects them automatically.", code: `// Contentful: Settings > Locales > set fallback\n// e.g. pt-BR → pt → en-US\n\n// SDK fetches pt-BR, falls back through chain:\nconst entry = await client.getEntry('ID', { locale: 'pt-BR' });\n// title is pt-BR if set, else pt, else en-US` },
    { id: 109, cat: "Localization", title: "Missing translations audit", tip: "Run this before launch — empty locale fields silently show nothing to users.", code: `const res = await client.withAllLocales.getEntries({ content_type: 'page' });\nconst LOCALES = ['en-US', 'de', 'fr'];\n\nres.items.forEach(item => {\n  LOCALES.forEach(locale => {\n    if (!item.fields.title?.[locale]) {\n      console.warn(\`Missing \${locale} title on \${item.sys.id}\`);\n    }\n  });\n});` },
    { id: 110, cat: "Localization", title: "RTL locale handling", tip: "Detect RTL locales and set dir attribute — Contentful stores content, your app handles direction.", code: `const RTL_LOCALES = ['ar', 'he', 'fa', 'ur'];\nconst isRtl = RTL_LOCALES.some(l => locale.startsWith(l));\n\n<html lang={locale} dir={isRtl ? 'rtl' : 'ltr'}>\n  {children}\n</html>` },
    { id: 111, cat: "Localization", title: "hreflang tags for SEO", tip: "hreflang tags are critical for international SEO — add them for all localised page variants.", code: `const LOCALES = ['en-US', 'de', 'fr'];\n\n// In <head>:\n{LOCALES.map(locale => (\n  <link\n    key={locale}\n    rel=\"alternate\"\n    hrefLang={locale}\n    href={\`https://example.com/\${locale}/\${slug}\`}\n  />\n))}` },
    { id: 112, cat: "Localization", title: "Locale in GraphQL", tip: "GraphQL locale filter is per-query — no global default like the SDK client.", code: `query {\n  blogPostCollection(locale: \"de\", limit: 5) {\n    items {\n      title  # returns German value\n      slug   # returns German slug\n    }\n  }\n}` },
    { id: 113, cat: "Localization", title: "Locale detection middleware", tip: "Detect and redirect to user's locale at the edge — no client-side flash.", code: `import { match } from '@formatjs/intl-localematcher';\nimport Negotiator from 'negotiator';\n\nexport function detectLocale(req) {\n  const headers = { 'accept-language': req.headers.get('accept-language') ?? '' };\n  const languages = new Negotiator({ headers }).languages();\n  return match(languages, ['en-US', 'de', 'fr'], 'en-US');\n}` },
    { id: 114, cat: "Localization", title: "Pluralisation with i18n", tip: "Use i18next or react-intl for pluralisation rules — Contentful just stores the string.", code: `// Contentful stores: { 'en-US': '{{count}} article' }\n// i18next handles plural forms:\nimport { useTranslation } from 'react-i18next';\nconst { t } = useTranslation();\nt('article_count', { count: 5 }); // → \"5 articles\"` },

    // ── WEBHOOKS (115–124) ────────────────────────────────────────────
    { id: 115, cat: "Webhooks", title: "Receive webhook (Next.js)", tip: "Always verify the webhook secret header — webhooks hit public URLs.", code: `export async function POST(req) {\n  const secret = req.headers.get('x-contentful-webhook-secret');\n  if (secret !== process.env.CONTENTFUL_WEBHOOK_SECRET) {\n    return new Response('Unauthorized', { status: 401 });\n  }\n  const body = await req.json();\n  // body.sys.id = entry ID\n  // body.sys.type = 'Entry' | 'Asset'\n  await revalidatePath('/blog');\n  return new Response('OK');\n}` },
    { id: 116, cat: "Webhooks", title: "Revalidate on publish", tip: "ISR tag revalidation is the most efficient response to a publish webhook.", code: `import { revalidateTag } from 'next/cache';\n\nexport async function POST(req) {\n  const body = await req.json();\n  const entryId = body.sys?.id;\n  revalidateTag(\`entry:\${entryId}\`);\n  revalidateTag('blog-list');\n  return Response.json({ revalidated: true });\n}` },
    { id: 117, cat: "Webhooks", title: "Webhook event types", tip: "Filter webhooks in Contentful to only the events you need — reduces noise.", code: `// Entry events:\n// create | save | auto_save | archive | unarchive\n// publish | unpublish | delete\n\n// Asset events:\n// create | save | auto_save | archive | unarchive\n// publish | unpublish | delete\n\n// body.sys.type → 'Entry' or 'Asset'\n// body.sys.revision → increments every save` },
    { id: 118, cat: "Webhooks", title: "HMAC webhook verification", tip: "Verify HMAC signatures to ensure webhooks are genuinely from Contentful.", code: `import crypto from 'crypto';\n\nfunction verifyWebhook(body, signature, secret) {\n  const hmac = crypto.createHmac('sha256', secret);\n  hmac.update(body);\n  const expected = hmac.digest('base64');\n  return crypto.timingSafeEqual(\n    Buffer.from(signature),\n    Buffer.from(expected)\n  );\n}` },
    { id: 119, cat: "Webhooks", title: "Idempotent webhook handler", tip: "Contentful retries failed webhooks — make your handler idempotent to avoid duplicate processing.", code: `export async function POST(req) {\n  const body = await req.json();\n  // Immediately acknowledge:\n  queueMicrotask(() => processWebhook(body)); // async\n  return new Response('OK', { status: 200 });  // fast response\n}\n\nasync function processWebhook(body) {\n  await syncToAlgolia(body.sys.id);\n  await invalidateCache(body.sys.id);\n}` },
    { id: 120, cat: "Webhooks", title: "Queue webhooks with BullMQ", tip: "Use a job queue for reliable webhook processing — gives you retries and observability.", code: `import { Queue } from 'bullmq';\nconst queue = new Queue('contentful-webhooks');\n\nexport async function POST(req) {\n  const body = await req.json();\n  await queue.add('process', {\n    entryId: body.sys.id,\n    action:  body.sys.type,\n  });\n  return new Response('Queued');\n}` },
    { id: 121, cat: "Webhooks", title: "Trigger Vercel deploy", tip: "Redeploy static sites when content changes using Vercel Deploy Hooks.", code: `async function triggerVercelDeploy() {\n  await fetch(process.env.VERCEL_DEPLOY_HOOK_URL, {\n    method: 'POST',\n  });\n}\n\n// In webhook handler:\nif (body.sys.eventType === 'publish') {\n  await triggerVercelDeploy();\n}` },
    { id: 122, cat: "Webhooks", title: "Slack notification on publish", tip: "Alert editors in Slack when content is published — no extra tools needed.", code: `async function notifySlack(entry) {\n  await fetch(process.env.SLACK_WEBHOOK_URL, {\n    method: 'POST',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({\n      text: \`📝 Published: *\${entry.fields.title?.['en-US']}*\n<https://yoursite.com/blog/\${entry.fields.slug?.['en-US']}|View>\`,\n    }),\n  });\n}` },
    { id: 123, cat: "Webhooks", title: "Audit log via webhooks", tip: "Stream all CMS changes to a database for a full editorial audit trail.", code: `export async function POST(req) {\n  const body = await req.json();\n  await db.insert(auditLog).values({\n    entryId:   body.sys.id,\n    action:    body.sys.type,\n    userId:    body.sys.updatedBy?.sys.id,\n    timestamp: new Date(),\n    snapshot:  JSON.stringify(body.fields),\n  });\n  return new Response('OK');\n}` },
    { id: 124, cat: "Webhooks", title: "Preview webhook on autosave", tip: "Trigger preview builds on autosave so editors see live updates without publishing.", code: `// Contentful event: Entry.auto_save\n// Fire preview rebuild on each autosave:\nexport async function POST(req) {\n  const body = await req.json();\n  if (body.sys.revision > 1) { // skip first save\n    await triggerPreviewDeploy(body.sys.id);\n  }\n  return new Response('OK');\n}` },

    // ── NEXT.JS (125–138) ─────────────────────────────────────────────
    { id: 125, cat: "Next.js Integration", title: "App Router fetch with tags", tip: "Tag fetch calls so webhooks can trigger granular on-demand revalidation.", code: `async function getBlogPosts() {\n  const res = await fetch(\n    \`https://cdn.contentful.com/spaces/\${SPACE_ID}/entries?content_type=blogPost\`,\n    {\n      headers: { Authorization: \`Bearer \${ACCESS_TOKEN}\` },\n      next: {\n        tags: ['blog-list'],\n        revalidate: 3600,\n      },\n    }\n  );\n  return res.json();\n}` },
    { id: 126, cat: "Next.js Integration", title: "getStaticProps (Pages Router)", tip: "Pass revalidate for ISR — don't build everything at deploy time for large sites.", code: `export async function getStaticProps({ params, locale }) {\n  const res = await client.getEntries({\n    content_type: 'page',\n    'fields.slug': params.slug,\n    locale: locale ?? 'en-US',\n    include: 2,\n  });\n  if (!res.items.length) return { notFound: true };\n  return {\n    props:      { page: res.items[0] },\n    revalidate: 60,\n  };\n}` },
    { id: 127, cat: "Next.js Integration", title: "Draft Mode / Preview", tip: "Combine Next.js Draft Mode with Contentful Preview API for live content previews.", code: `// app/api/draft/route.ts\nimport { draftMode } from 'next/headers';\nexport async function GET(req) {\n  const { searchParams } = new URL(req.url);\n  if (searchParams.get('secret') !== process.env.PREVIEW_SECRET)\n    return new Response('Invalid token', { status: 401 });\n  (await draftMode()).enable();\n  return Response.redirect(new URL(searchParams.get('slug') ?? '/', req.url));\n}\n\n// In page:\nconst { isEnabled } = await draftMode();\nconst useClient = isEnabled ? previewClient : client;` },
    { id: 128, cat: "Next.js Integration", title: "generateStaticParams", tip: "Only fetch slug fields — makes param generation fast even for thousands of entries.", code: `export async function generateStaticParams() {\n  const res = await client.getEntries({\n    content_type: 'blogPost',\n    select: ['fields.slug'],\n    limit: 1000,\n  });\n  return res.items.map(item => ({ slug: item.fields.slug }));\n}` },
    { id: 129, cat: "Next.js Integration", title: "Metadata API", tip: "Generate dynamic OG tags from Contentful SEO fields for every page.", code: `export async function generateMetadata({ params }) {\n  const [page] = (await client.getEntries({\n    content_type: 'page',\n    'fields.slug': params.slug,\n    select: ['fields.seoTitle', 'fields.seoDescription', 'fields.ogImage'],\n  })).items;\n\n  return {\n    title:       page.fields.seoTitle,\n    description: page.fields.seoDescription,\n    openGraph: {\n      images: [{ url: 'https:' + page.fields.ogImage?.fields.file.url + '?w=1200&h=630&fit=fill' }],\n    },\n  };\n}` },
    { id: 130, cat: "Next.js Integration", title: "Sitemap generation", tip: "Generate sitemap.xml at build time from Contentful for full SEO coverage.", code: `// app/sitemap.ts\nexport default async function sitemap() {\n  const res = await client.getEntries({\n    content_type: 'blogPost',\n    select: ['fields.slug', 'sys.updatedAt'],\n    limit: 1000,\n  });\n  return res.items.map(item => ({\n    url:            \`https://example.com/blog/\${item.fields.slug}\`,\n    lastModified:   new Date(item.sys.updatedAt),\n    changeFrequency: 'weekly',\n    priority: 0.8,\n  }));\n}` },
    { id: 131, cat: "Next.js Integration", title: "Streaming with Suspense", tip: "Wrap Contentful fetches in Suspense boundaries for streaming SSR.", code: `import { Suspense } from 'react';\n\nasync function Posts() {\n  const posts = await client.getEntries({ content_type: 'blogPost' });\n  return <PostList items={posts.items} />;\n}\n\nexport default function Page() {\n  return (\n    <main>\n      <Hero />\n      <Suspense fallback={<PostsSkeleton />}>\n        <Posts />\n      </Suspense>\n    </main>\n  );\n}` },
    { id: 132, cat: "Next.js Integration", title: "ISR — revalidate segment", tip: "ISR is the sweet spot for content sites — static performance + content freshness.", code: `// Page-level (Pages Router):\nexport async function getStaticProps() {\n  return { props: { ... }, revalidate: 60 };\n}\n\n// Route segment (App Router):\nexport const revalidate = 60; // applies to whole segment\n\n// Or per-fetch:\nfetch(url, { next: { revalidate: 60 } });` },
    { id: 133, cat: "Next.js Integration", title: "Route handler as CMS proxy", tip: "Proxy all Contentful requests via your own API — never expose CDA tokens to the client.", code: `// app/api/posts/route.ts\nexport async function GET(req) {\n  const { searchParams } = new URL(req.url);\n  const slug = searchParams.get('slug');\n  const res = await client.getEntries({\n    content_type: 'blogPost',\n    'fields.slug': slug ?? undefined,\n    limit: slug ? 1 : 10,\n  });\n  return Response.json(res.items, {\n    headers: { 'Cache-Control': 'public, s-maxage=60' },\n  });\n}` },
    { id: 134, cat: "Next.js Integration", title: "useContentful SWR hook", tip: "SWR + a client-side hook is great for search, filters, and dynamic user interactions.", code: `import useSWR from 'swr';\n\nconst fetcher = ([type, params]) =>\n  client.getEntries({ content_type: type, ...params }).then(r => r.items);\n\nexport function useEntries(contentType, params = {}) {\n  return useSWR([contentType, params], fetcher, {\n    revalidateOnFocus: false,\n  });\n}\n\nconst { data: posts, isLoading } = useEntries('blogPost', { limit: 10 });` },
    { id: 135, cat: "Next.js Integration", title: "unstable_cache wrapper", tip: "Wrap Contentful calls in unstable_cache for cross-request deduplication in the App Router.", code: `import { unstable_cache } from 'next/cache';\n\nconst getCachedPosts = unstable_cache(\n  async (limit) =>\n    client.getEntries({ content_type: 'blogPost', limit }),\n  ['contentful-posts'],\n  { tags: ['blog-list'], revalidate: 3600 }\n);\n\nconst posts = await getCachedPosts(10);` },
    { id: 136, cat: "Next.js Integration", title: "Parallel data fetching", tip: "Promise.all halves load time by fetching independent resources simultaneously.", code: `const [posts, categories, settings] = await Promise.all([\n  client.getEntries({ content_type: 'blogPost',    limit: 10 }),\n  client.getEntries({ content_type: 'category',    limit: 50 }),\n  client.getEntries({ content_type: 'siteSettings', limit: 1  }),\n]);` },
    { id: 137, cat: "Next.js Integration", title: "Content-driven navigation", tip: "Store nav structure in Contentful — gives marketing teams full menu control.", code: `const nav = await client.getEntry('NAV_ENTRY_ID', { include: 3 });\n\nfunction Nav({ items }) {\n  return (\n    <nav>\n      {items.map(item => (\n        <NavItem key={item.sys.id} item={item.fields} />\n      ))}\n    </nav>\n  );\n}` },
    { id: 138, cat: "Next.js Integration", title: "Preview bar component", tip: "Show a floating bar in draft mode so editors always know they are in preview.", code: `export function PreviewBar({ isPreview }) {\n  if (!isPreview) return null;\n  return (\n    <div style={{\n      position: 'fixed', bottom: 0, left: 0, right: 0,\n      background: '#e8521a', color: '#fff',\n      padding: '8px 16px', textAlign: 'center', zIndex: 9999\n    }}>\n      Preview mode —{' '}\n      <a href=\"/api/exit-draft\" style={{ color: '#fff', textDecoration: 'underline' }}>Exit</a>\n    </div>\n  );\n}` },

    // ── TYPESCRIPT (139–150) ──────────────────────────────────────────
    { id: 139, cat: "TypeScript", title: "Generate types from model", tip: "Use the official generator to avoid manual type drift — run it after schema changes.", code: `npm install -D contentful-typescript-codegen\n\n# Generate types:\nnpx contentful-typescript-codegen \\\n  --space-id \${SPACE_ID} \\\n  --access-token \${ACCESS_TOKEN} \\\n  -o src/types/contentful.d.ts` },
    { id: 140, cat: "TypeScript", title: "Define entry skeleton", tip: "Use EntryFieldTypes for field typing — much more precise than any.", code: `import type { Entry, EntryFieldTypes } from 'contentful';\n\ninterface BlogPostSkeleton {\n  contentTypeId: 'blogPost';\n  fields: {\n    title:       EntryFieldTypes.Text;\n    slug:        EntryFieldTypes.Symbol;\n    body:        EntryFieldTypes.RichText;\n    publishDate: EntryFieldTypes.Date;\n    author:      EntryFieldTypes.EntryLink<AuthorSkeleton>;\n    coverImage:  EntryFieldTypes.AssetLink;\n    tags:        EntryFieldTypes.Array<EntryFieldTypes.Symbol>;\n  };\n}\n\ntype BlogPost = Entry<BlogPostSkeleton>;` },
    { id: 141, cat: "TypeScript", title: "Typed getEntries", tip: "Pass your skeleton type as a generic to getEntries for fully typed responses.", code: `const res = await client.getEntries<BlogPostSkeleton>({\n  content_type: 'blogPost',\n  limit: 10,\n});\n\n// Fully typed:\n// res.items[0].fields.title         → string\n// res.items[0].fields.author.fields → AuthorFields` },
    { id: 142, cat: "TypeScript", title: "Content type guard", tip: "Type guards prevent runtime errors when handling mixed entry types in dynamic renderers.", code: `function isBlogPost(entry: Entry<any>): entry is BlogPost {\n  return entry.sys.contentType.sys.id === 'blogPost';\n}\n\nfunction DynamicSection({ entry }: { entry: Entry<any> }) {\n  if (isBlogPost(entry)) return <BlogCard post={entry} />;\n  if (isCallout(entry))  return <Callout data={entry} />;\n  return null;\n}` },
    { id: 143, cat: "TypeScript", title: "Discriminated union sections", tip: "Discriminated unions for section/block types give you exhaustive type safety.", code: `type Section =\n  | Entry<HeroSkeleton>\n  | Entry<FeatureGridSkeleton>\n  | Entry<TestimonialsSkeleton>;\n\nfunction renderSection(section: Section) {\n  switch (section.sys.contentType.sys.id) {\n    case 'hero':         return <Hero         {...section.fields} />;\n    case 'featureGrid':  return <FeatureGrid  {...section.fields} />;\n    case 'testimonials': return <Testimonials {...section.fields} />;\n  }\n}` },
    { id: 144, cat: "TypeScript", title: "Document type for rich text", tip: "Use Document from @contentful/rich-text-types for type-safe rich text props.", code: `import type { Document } from '@contentful/rich-text-types';\n\ninterface RichTextProps {\n  document:  Document;\n  className?: string;\n}\n\nfunction RichTextRenderer({ document, className }: RichTextProps) {\n  return (\n    <div className={className}>\n      {documentToReactComponents(document, options)}\n    </div>\n  );\n}` },
    { id: 145, cat: "TypeScript", title: "Asset type helper", tip: "A utility function for type-safe asset URL extraction.", code: `import type { Asset, AssetFields } from 'contentful';\n\nfunction getImageUrl(asset: Asset, width = 800): string {\n  const url = (asset.fields as AssetFields).file?.url;\n  if (!url) throw new Error('Asset has no file URL');\n  return \`https:\${url}?w=\${width}&fm=webp\`;\n}` },
    { id: 146, cat: "TypeScript", title: "Zod validation schema", tip: "Validate Contentful responses at runtime with Zod for safety in critical paths.", code: `import { z } from 'zod';\n\nconst BlogPostSchema = z.object({\n  sys: z.object({ id: z.string(), updatedAt: z.string() }),\n  fields: z.object({\n    title:       z.string(),\n    slug:        z.string().regex(/^[a-z0-9-]+$/),\n    publishDate: z.string().datetime(),\n  }),\n});\n\nconst validated = BlogPostSchema.parse(rawEntry);` },
    { id: 147, cat: "TypeScript", title: "Infer field types from skeleton", tip: "Use TypeScript utility types to extract precise field types.", code: `type PostFields = BlogPostSkeleton['fields'];\ntype PostTitle  = PostFields['title']['type']; // → string\n\n// Extract resolved entry type:\ntype ResolvedPost = Entry<BlogPostSkeleton, 'WITHOUT_UNRESOLVABLE_LINKS'>;` },
    { id: 148, cat: "TypeScript", title: "Mock factory for tests", tip: "Type-safe mock factories make unit tests easy and catch schema drift.", code: `export function createMockPost(overrides: Partial<BlogPost['fields']> = {}): BlogPost {\n  return {\n    sys: { id: 'mock-1', type: 'Entry', contentType: { sys: { id: 'blogPost' } } } as any,\n    fields: {\n      title:       'Test Post',\n      slug:        'test-post',\n      publishDate: '2024-01-01',\n      body:        { nodeType: 'document', content: [], data: {} } as any,\n      ...overrides,\n    },\n    metadata: { tags: [] },\n  };\n}` },
    { id: 149, cat: "TypeScript", title: "Renderer component pattern", tip: "A strongly typed map from content type ID to component eliminates switch/if chains.", code: `const RENDERERS: Record<string, React.ComponentType<any>> = {\n  hero:          HeroSection,\n  featureGrid:   FeatureGrid,\n  testimonials:  Testimonials,\n  callout:       Callout,\n  richTextBlock: RichTextBlock,\n};\n\nfunction DynamicSection({ entry }: { entry: Entry<any> }) {\n  const Component = RENDERERS[entry.sys.contentType.sys.id];\n  if (!Component) return null;\n  return <Component {...entry.fields} />;\n}` },
    { id: 150, cat: "TypeScript", title: "CMA TypeScript types", tip: "Import CMA types for fully typed management operations.", code: `import type {\n  Entry,\n  Environment,\n  ContentType,\n  Asset,\n} from 'contentful-management';\n\nasync function publishEntry(env: Environment, id: string): Promise<Entry> {\n  let entry = await env.getEntry(id);\n  return entry.publish();\n}` },

    // ── PERFORMANCE & CACHING (151–162) ───────────────────────────────
    { id: 151, cat: "Performance & Caching", title: "Cache API responses", tip: "Contentful responses are stable per publish version — cache aggressively.", code: `import { unstable_cache } from 'next/cache';\n\nconst getCachedEntries = unstable_cache(\n  async (contentType) =>\n    client.getEntries({ content_type: contentType }).then(r => r.items),\n  ['contentful-entries'],\n  { tags: ['contentful'], revalidate: 3600 }\n);` },
    { id: 152, cat: "Performance & Caching", title: "Redis caching layer", tip: "Redis gives sub-millisecond repeat reads — perfect for heavily-trafficked pages.", code: `import { createClient } from 'redis';\nconst redis = createClient({ url: process.env.REDIS_URL });\n\nasync function getCachedEntry(id) {\n  const cached = await redis.get(\`ctf:entry:\${id}\`);\n  if (cached) return JSON.parse(cached);\n  const entry = await client.getEntry(id, { include: 2 });\n  await redis.setEx(\`ctf:entry:\${id}\`, 300, JSON.stringify(entry));\n  return entry;\n}` },
    { id: 153, cat: "Performance & Caching", title: "Rate limits", tip: "CDA: 55 req/s per space. CMA: 7 req/s. Use exponential backoff on 429s.", code: `async function fetchWithRetry(fn, retries = 5) {\n  for (let i = 0; i < retries; i++) {\n    try {\n      return await fn();\n    } catch (err) {\n      if (err.status === 429) {\n        const wait = Math.pow(2, i) * 500; // 500ms, 1s, 2s, 4s, 8s\n        await new Promise(r => setTimeout(r, wait));\n      } else throw err;\n    }\n  }\n  throw new Error('Max retries exceeded');\n}` },
    { id: 154, cat: "Performance & Caching", title: "Edge caching headers", tip: "Return Contentful data with s-maxage so Vercel/Cloudflare Edge caches it globally.", code: `export async function GET() {\n  const posts = await client.getEntries({ content_type: 'blogPost' });\n  return Response.json(posts.items, {\n    headers: {\n      'Cache-Control': 'public, s-maxage=300, stale-while-revalidate=600',\n    },\n  });\n}` },
    { id: 155, cat: "Performance & Caching", title: "Request deduplication", tip: "Deduplicate identical in-flight requests to avoid multiple identical API calls per render.", code: `const cache = new Map();\n\nfunction deduped(key, fn) {\n  if (!cache.has(key)) {\n    cache.set(key, fn().finally(() => cache.delete(key)));\n  }\n  return cache.get(key);\n}\n\nconst posts = await deduped('blogPosts', () =>\n  client.getEntries({ content_type: 'blogPost' })\n);` },
    { id: 156, cat: "Performance & Caching", title: "Avoid over-fetching", tip: "Use select to only fetch fields you render — huge payload savings on large entry sets.", code: `// ❌ Fetches everything including 15 unused fields:\nconst res = await client.getEntries({ content_type: 'article' });\n\n// ✅ Only fetch what you render in the list:\nconst res = await client.getEntries({\n  content_type: 'article',\n  select: ['sys.id','fields.title','fields.slug',\n           'fields.publishDate','fields.summary','fields.coverImage'],\n});` },
    { id: 157, cat: "Performance & Caching", title: "Bundle tree shaking", tip: "Named imports are tree-shakeable — avoids pulling in the full SDK in client bundles.", code: `// ✅ Named imports (tree-shakeable):\nimport { createClient } from 'contentful';\nimport { documentToReactComponents } from '@contentful/rich-text-react-renderer';\nimport { BLOCKS } from '@contentful/rich-text-types';\n\n// Keep contentful-management server-side only\n// (add to server-only.ts or use in API routes)` },
    { id: 158, cat: "Performance & Caching", title: "Staggered revalidation", tip: "Vary revalidate times to spread cache misses and avoid thundering-herd on ISR.", code: `// Vary revalidate by slug hash to spread cache misses:\nfunction revalidateSeconds(slug) {\n  const hash = slug.split('').reduce((a, c) => a + c.charCodeAt(0), 0);\n  return 60 + (hash % 60); // between 60-120s\n}` },
    { id: 159, cat: "Performance & Caching", title: "Measure Contentful TTFB", tip: "Instrument fetches to track how long Contentful calls take — target <200ms with edge caching.", code: `const start = performance.now();\nconst res   = await client.getEntries({ content_type: 'page' });\nconst ttfb  = performance.now() - start;\nconsole.log(\`Contentful fetch: \${ttfb.toFixed(0)}ms\`);\n\n// Track in Datadog:\nmetrics.histogram('contentful.fetch.duration', ttfb, { content_type: 'page' });` },
    { id: 160, cat: "Performance & Caching", title: "Flatten deep nesting", tip: "Flatten your content model if you need include > 3 — deep nesting hurts performance.", code: `// ❌ Deep nesting: Page → Section → Block → Component → Asset (include: 4)\n// This fetches enormous payloads.\n\n// ✅ Flatten: Page → Block (include: 1)\n// Or use GraphQL to fetch exactly the fields you need at each level.` },
    { id: 161, cat: "Performance & Caching", title: "SWR stale-while-revalidate", tip: "SWR shows stale data instantly while refreshing in the background — perfect UX.", code: `import useSWR from 'swr';\n\nconst { data } = useSWR(\n  ['getEntries', { content_type: 'product', limit: 20 }],\n  ([, params]) => client.getEntries(params).then(r => r.items),\n  {\n    dedupingInterval:  60_000,\n    revalidateOnFocus: false,\n    fallbackData:      serverSideProps.products,\n  }\n);` },
    { id: 162, cat: "Performance & Caching", title: "CDN cache-control headers", tip: "Contentful CDA includes s-maxage=300 by default — respect it in your middleware.", code: `// Contentful CDA responses include:\n// Cache-Control: public, max-age=0, s-maxage=300\n// X-Contentful-Request-Id: for debugging\n\n// Forward to Vercel Edge in middleware:\nresponse.headers.set(\n  'Cache-Control',\n  'public, s-maxage=300, stale-while-revalidate=600'\n);` },

    // ── CONTENT MODELING (163–174) ────────────────────────────────────
    { id: 163, cat: "Content Modeling", title: "Reference field patterns", tip: "Prefer entry links over duplicating content — single source of truth avoids drift.", code: `// ✅ Author is a separate entry, linked from posts:\n// BlogPost.fields.author → Entry<Author>\n\n// ❌ Copy-pasting author name/bio into every post:\n// BlogPost.fields.authorName: 'Jane'  (duplicated!)\n// BlogPost.fields.authorBio: 'Jane is...' (duplicated!)` },
    { id: 164, cat: "Content Modeling", title: "Modular page builder", tip: "A 'sections' Array<EntryLink> field enables drag-and-drop page building for editors.", code: `// Page content type:\n// fields.sections: Array<EntryLink>\n//   → allowed types: Hero, FeatureGrid, Testimonials, CTA\n\nfunction Page({ entry }) {\n  return (\n    <main>\n      {entry.fields.sections.map(section => (\n        <DynamicSection key={section.sys.id} entry={section} />\n      ))}\n    </main>\n  );\n}` },
    { id: 165, cat: "Content Modeling", title: "Taxonomy / tag content type", tip: "Use a Tag content type when you need rich tag data like descriptions or colors.", code: `// Tag content type: { name, slug, description, color }\n// BlogPost.fields.tags: Array<EntryLink<Tag>>\n\n// Filter posts by tag slug:\nconst res = await client.getEntries({\n  content_type: 'blogPost',\n  'fields.tags.sys.id': tagEntryId,\n});` },
    { id: 166, cat: "Content Modeling", title: "Global settings singleton", tip: "A Settings entry stores site-wide config — query it once and pass via React context.", code: `// SiteSettings content type (limit: 1 entry)\n// { siteName, defaultSeoDesc, mainNav, footerLinks }\n\nconst [settings] = (await client.getEntries({\n  content_type: 'siteSettings',\n  limit: 1,\n  include: 3,\n})).items;` },
    { id: 167, cat: "Content Modeling", title: "Ordered list via integer field", tip: "Add a sortOrder: Integer field for editorially-controlled ordering.", code: `const res = await client.getEntries({\n  content_type: 'faqItem',\n  order: 'fields.sortOrder',\n});` },
    { id: 168, cat: "Content Modeling", title: "Short text vs long text", tip: "Symbol is indexed and filterable. Text is searchable but not filterable. Choose carefully.", code: `// Symbol  → filterable, max 256 chars, use for slugs/titles/IDs\n// Text    → full-text searchable, unlimited, use for descriptions\n// RichText → structured document, use for body content\n// Integer / Decimal → for numbers, ratings, prices` },
    { id: 169, cat: "Content Modeling", title: "Field validations in CMS", tip: "Add validations in the content model — saves client-side validation code.", code: `// Slug regex:\n{ \"regexp\": { \"pattern\": \"^[a-z0-9]+(?:-[a-z0-9]+)*$\" } }\n\n// URL field:\n{ \"type\": \"Symbol\", \"validations\": [\n  { \"regexp\": { \"pattern\": \"^https?://\" } }\n] }\n\n// Character limit:\n{ \"size\": { \"min\": 1, \"max\": 160 } }` },
    { id: 170, cat: "Content Modeling", title: "Slug auto-generation app", tip: "Use the Contentful App Framework to auto-generate slugs from title on entry creation.", code: `// In a Contentful App (field editor):\nsdk.entry.fields.title.onValueChanged(value => {\n  const slug = value\n    ?.toLowerCase().trim()\n    .replace(/[^a-z0-9\\s-]/g, '')\n    .replace(/\\s+/g, '-');\n  sdk.entry.fields.slug.setValue(slug);\n});` },
    { id: 171, cat: "Content Modeling", title: "Dynamic forms via CMS", tip: "Model form fields in Contentful so marketing teams can build forms without code changes.", code: `// FormField: { label, name, type (text|email|select), required, options }\n// Page.fields.form → Entry<Form>\n// Form.fields.fields → Entry<FormField>[]\n\nfunction DynamicForm({ form }) {\n  return (\n    <form>\n      {form.fields.fields.map(f =>\n        <DynamicField key={f.sys.id} field={f} />\n      )}\n    </form>\n  );\n}` },
    { id: 172, cat: "Content Modeling", title: "Many-to-many junction entry", tip: "Model many-to-many relationships with a junction entry — Contentful has no native M2M.", code: `// Author writes for many Outlets; Outlet has many Authors\n// → Junction: AuthorOutlet {\n//     author:  EntryLink<Author>\n//     outlet:  EntryLink<Outlet>\n//     role:    Symbol\n//   }\n\nconst memberships = await client.getEntries({\n  content_type: 'authorOutlet',\n  'fields.author.sys.id': authorId,\n});` },
    { id: 173, cat: "Content Modeling", title: "Content versioning field", tip: "Add a schemaVersion field so query logic can target a specific schema version.", code: `// Add schemaVersion: Integer field to content types\n// Increment when breaking schema changes happen\n\nconst res = await client.getEntries({\n  content_type: 'product',\n  'fields.schemaVersion': 2,\n});` },
    { id: 174, cat: "Content Modeling", title: "Slug uniqueness check", tip: "Contentful doesn't enforce slug uniqueness — add a CI check or Contentful App.", code: `// CI check — fail build on duplicate slugs:\nconst res = await client.getEntries({\n  content_type: 'page',\n  select: ['fields.slug'],\n  limit: 1000,\n});\nconst slugs = res.items.map(i => i.fields.slug);\nconst dupes = slugs.filter((s, i) => slugs.indexOf(s) !== i);\nif (dupes.length) throw new Error(\`Duplicate slugs: \${dupes.join(', ')}\`);` },

    // ── MIGRATIONS & CLI (175–186) ────────────────────────────────────
    { id: 175, cat: "Migrations & CLI", title: "Install Contentful CLI", tip: "CLI is essential for migrations, environment management, and scripting deployments.", code: `npm install -g contentful-cli\ncontentful login        # opens browser OAuth\ncontentful space list\ncontentful space use --space-id YOUR_SPACE_ID` },
    { id: 176, cat: "Migrations & CLI", title: "Write a migration script", tip: "Never manually edit content models in production — always use migration scripts.", code: `// migrations/001-add-seo-fields.js\nmodule.exports = function(migration) {\n  const blogPost = migration.editContentType('blogPost');\n\n  blogPost.createField('seoTitle')\n    .name('SEO title')\n    .type('Symbol')\n    .required(false);\n\n  blogPost.createField('seoDescription')\n    .name('SEO description')\n    .type('Text')\n    .validations([{ size: { max: 160 } }]);\n};` },
    { id: 177, cat: "Migrations & CLI", title: "Run migration", tip: "Always test on staging first — never run migrations directly on master.", code: `# Run against staging first:\ncontentful space migration \\\n  --space-id YOUR_SPACE_ID \\\n  --environment-id staging \\\n  migrations/001-add-seo-fields.js\n\n# Promote to master:\ncontentful space migration \\\n  --environment-id master \\\n  migrations/001-add-seo-fields.js` },
    { id: 178, cat: "Migrations & CLI", title: "Dry run migration", tip: "Run --dry-run to preview changes before applying — no side effects.", code: `contentful space migration \\\n  --space-id YOUR_SPACE \\\n  --environment-id staging \\\n  --dry-run \\\n  migrations/001-add-seo-fields.js\n\n# Output shows intent:\n# [intent] Create field seoTitle on blogPost\n# [intent] Create field seoDescription on blogPost` },
    { id: 179, cat: "Migrations & CLI", title: "Rollback script", tip: "Write a companion rollback script for every migration — test it before deploying.", code: `// migrations/001-add-seo-fields.rollback.js\nmodule.exports = function(migration) {\n  const blogPost = migration.editContentType('blogPost');\n  blogPost.deleteField('seoTitle');\n  blogPost.deleteField('seoDescription');\n};` },
    { id: 180, cat: "Migrations & CLI", title: "Export / import space", tip: "Export a snapshot before major changes — fast rollback if something goes wrong.", code: `# Export full space:\ncontentful space export \\\n  --space-id YOUR_SPACE_ID \\\n  --content-file backup-$(date +%Y%m%d).json\n\n# Import into another space:\ncontentful space import \\\n  --space-id TARGET_SPACE_ID \\\n  --content-file backup-20240101.json` },
    { id: 181, cat: "Migrations & CLI", title: "Clone environment", tip: "Clone to safely test migrations without touching production.", code: `# Via CLI:\ncontentful space environment create \\\n  --source-environment-id master \\\n  --name staging-$(date +%Y%m%d)\n\n# Or via CMA:\nawait space.createEnvironmentWithId(\n  'staging-20240101',\n  { name: 'Staging 2024-01-01' },\n  'master'\n);` },
    { id: 182, cat: "Migrations & CLI", title: "Environment aliases", tip: "Point the master alias at a release environment for zero-downtime schema rollouts.", code: `# Create release environment:\ncontentful space environment create --name release-v2\n\n# Run migrations + QA on release-v2\n\n# Flip alias when ready:\ncontentful space environment alias update master \\\n  --target-environment-id release-v2` },
    { id: 183, cat: "Migrations & CLI", title: "Bulk import via script", tip: "Scripted bulk import is faster and auditable vs manual entry creation.", code: `const items = JSON.parse(fs.readFileSync('products.json', 'utf8'));\n\nfor (const item of items) {\n  const entry = await env.createEntry('product', {\n    fields: {\n      name:  { 'en-US': item.name },\n      price: { 'en-US': item.price },\n      sku:   { 'en-US': item.sku },\n    },\n  });\n  await entry.publish();\n  console.log('Created:', entry.sys.id);\n}` },
    { id: 184, cat: "Migrations & CLI", title: "Field reorder migration", tip: "Field order in Contentful editor is set via moveField — improves editor experience.", code: `module.exports = function(migration) {\n  const ct = migration.editContentType('blogPost');\n  ct.moveField('seoTitle').afterField('body');\n  ct.moveField('seoDescription').afterField('seoTitle');\n  ct.moveField('ogImage').afterField('seoDescription');\n};` },
    { id: 185, cat: "Migrations & CLI", title: "List content types script", tip: "Quick audit of your space — useful before starting a migration or onboarding.", code: `const cts = await env.getContentTypes({ limit: 200 });\ncts.items.forEach(ct => {\n  console.log(\n    ct.sys.id.padEnd(20),\n    ct.name.padEnd(30),\n    ct.fields.length, 'fields'\n  );\n});` },
    { id: 186, cat: "Migrations & CLI", title: "CI migration validation", tip: "Add migration validation as a CI step — catch schema errors before they reach production.", code: `# package.json:\n\"validate:migration\": \"contentful space migration --dry-run migrations/latest.js\"\n\n# GitHub Actions step:\n- name: Validate migration\n  run: npm run validate:migration\n  env:\n    CONTENTFUL_SPACE_ID: \${{ secrets.CONTENTFUL_SPACE_ID }}\n    CONTENTFUL_MANAGEMENT_TOKEN: \${{ secrets.CONTENTFUL_MANAGEMENT_TOKEN }}` },

    // ── TIPS & TRICKS (187–200) ───────────────────────────────────────
    { id: 187, cat: "Tips & Tricks", title: "Never expose tokens client-side", tip: "CDA tokens are read-only but still identify your space — proxy via your own API route.", code: `// ❌ Token in browser bundle:\nconst client = createClient({ accessToken: process.env.NEXT_PUBLIC_CTF_TOKEN });\n\n// ✅ Proxy via API route:\n// /app/api/contentful/route.ts → adds auth, forwards to CDA\n// Client calls /api/contentful?content_type=blogPost` },
    { id: 188, cat: "Tips & Tricks", title: "Zero-downtime schema changes", tip: "Follow expand/contract: add new field, migrate data, remove old field.", code: `// Step 1: Add new field (backward-compatible migration)\n// Step 2: Migrate data to new field (script)\n// Step 3: Deploy code that uses new field\n// Step 4: Remove old field (migration)\n// Never rename/delete without expand/contract` },
    { id: 189, cat: "Tips & Tricks", title: "Contentful + Algolia sync", tip: "Push entries to Algolia via webhook for blazing-fast search — Contentful is not a search engine.", code: `import algoliasearch from 'algoliasearch';\nconst index = algoliasearch(APP_ID, KEY).initIndex('posts');\n\nasync function onPublish(entry) {\n  await index.saveObject({\n    objectID: entry.sys.id,\n    title:    entry.fields.title?.['en-US'],\n    slug:     entry.fields.slug?.['en-US'],\n    excerpt:  entry.fields.excerpt?.['en-US'],\n  });\n}\nasync function onDelete(entry) {\n  await index.deleteObject(entry.sys.id);\n}` },
    { id: 190, cat: "Tips & Tricks", title: "Content health checks", tip: "Run automated checks on entries for SEO, broken links, and missing images.", code: `async function runHealthCheck() {\n  const res = await client.getEntries({ content_type: 'blogPost', limit: 200 });\n  const issues = [];\n  for (const post of res.items) {\n    if (!post.fields.seoTitle)    issues.push({ id: post.sys.id, issue: 'Missing SEO title' });\n    if (!post.fields.coverImage)  issues.push({ id: post.sys.id, issue: 'Missing cover image' });\n    if ((post.fields.seoDescription ?? '').length > 160)\n      issues.push({ id: post.sys.id, issue: 'SEO description too long' });\n  }\n  return issues;\n}` },
    { id: 191, cat: "Tips & Tricks", title: "Mock Contentful in tests", tip: "Mock the client to avoid network calls — fast, deterministic, and works offline.", code: `vi.mock('contentful', () => ({\n  createClient: () => ({\n    getEntries: vi.fn().mockResolvedValue({\n      items: [{ sys: { id: '1' }, fields: { title: 'Test' } }],\n      total: 1,\n    }),\n    getEntry: vi.fn().mockResolvedValue({ /* ... */ }),\n  }),\n}));` },
    { id: 192, cat: "Tips & Tricks", title: "Track changes in git", tip: "Export space content to JSON and commit — full history + PR review for content changes.", code: `# In CI after each merge:\ncontentful space export \\\n  --content-only \\\n  --content-file content/contentful-export.json\n\ngit add content/contentful-export.json\ngit commit -m \"chore: sync contentful content\"` },
    { id: 193, cat: "Tips & Tricks", title: "Contentful Apps SDK", tip: "Build custom field editors, sidebar widgets, and page extensions with the App Framework.", code: `npm install @contentful/app-sdk @contentful/f36-components\n\nimport { init } from '@contentful/app-sdk';\ninit(sdk => {\n  const { field, entry, space } = sdk;\n  field.getValue();     // current field value\n  field.setValue('x');  // update field\n  entry.fields.title.getValue();\n});` },
    { id: 194, cat: "Tips & Tricks", title: "Circular reference detection", tip: "Circular links crash include resolution — detect and break them in your data layer.", code: `function resolveWithoutCirculars(entry, seen = new Set()) {\n  if (seen.has(entry.sys.id)) return { sys: entry.sys }; // break cycle\n  seen.add(entry.sys.id);\n  // recurse into linked fields...\n}` },
    { id: 195, cat: "Tips & Tricks", title: "Contentful Compose app", tip: "Use the Compose app for page-level content ordering — it's the official page builder UI.", code: `// Compose creates a 'page' content type\n// with a drag-and-drop 'content' field array\n\nfunction ComposePage({ content }) {\n  return content.map(block => (\n    <DynamicSection key={block.sys.id} entry={block} />\n  ));\n}` },
    { id: 196, cat: "Tips & Tricks", title: "Contentful + TypeSense search", tip: "TypeSense is open-source alternative to Algolia — sync Contentful via webhook.", code: `import Typesense from 'typesense';\nconst ts = new Typesense.Client({\n  nodes:  [{ url: process.env.TYPESENSE_URL }],\n  apiKey: process.env.TYPESENSE_ADMIN_KEY,\n});\n\nawait ts.collections('posts').documents().upsert({\n  id:    entry.sys.id,\n  title: entry.fields.title?.['en-US'],\n  body:  documentToPlainTextString(entry.fields.body?.['en-US']),\n  slug:  entry.fields.slug?.['en-US'],\n});` },
    { id: 197, cat: "Tips & Tricks", title: "Structured clone before mutation", tip: "Deep-clone entries before transforming — avoids mutating cached references.", code: `const entry = await client.getEntry('ENTRY_ID');\n\n// ❌ Mutates the cached object:\nentry.fields.title = 'Modified';\n\n// ✅ Clone first:\nconst data = structuredClone(entry.fields);\ndata.title = 'Modified';` },
    { id: 198, cat: "Tips & Tricks", title: "Space template bootstrap", tip: "Bootstrap new client spaces from a template export — perfect for multi-tenant setups.", code: `# Export reference space:\ncontentful space export \\\n  --space-id TEMPLATE_SPACE \\\n  --content-file template.json\n\n# Import into new client space:\ncontentful space import \\\n  --space-id NEW_CLIENT_SPACE \\\n  --content-file template.json` },
    { id: 199, cat: "Tips & Tricks", title: "Content diff for PRs", tip: "Show editors a diff of what changed in entries before a PR merges.", code: `// Get entry version history via CMA:\nconst snapshots = await env.getEntrySnapshots('ENTRY_ID');\nconst prev = snapshots.items[1].fields;\nconst curr = snapshots.items[0].fields;\n// Diff fields.title['en-US'], fields.body['en-US'], etc.\n// Surface in PR comment via GitHub Actions` },
    { id: 200, cat: "Tips & Tricks", title: "Key docs & resources", tip: "Bookmark these — the official docs cover edge cases that cost hours to debug.", code: `// Official documentation:\n// CDA:      https://www.contentful.com/developers/docs/references/content-delivery-api/\n// CMA:      https://www.contentful.com/developers/docs/references/content-management-api/\n// GraphQL:  https://www.contentful.com/developers/docs/references/graphql/\n// SDK:      https://github.com/contentful/contentful.js\n// Images:   https://www.contentful.com/developers/docs/references/images-api/\n// Status:   https://www.contentfulstatus.com/\n// Community: https://community.contentful.com/` },
];

// ── Helpers ──────────────────────────────────────────────────────────
function hlCode(code) {
    const tokens = [];
    let esc = code.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");

    // 1. Extract comments and strings (to avoid highlighting keywords inside them)
    esc = esc.replace(/(\/\/.*$)|(#.*$)|(`[^`]*`)|('[^']*')|("(?:[^"\\]|\\.)*")/gm, (match, c, h) => {
        const i = tokens.length;
        if (c || h) {
            tokens.push(`<span style="color:#6a9955;font-style:italic">${match}</span>`);
        } else {
            tokens.push(`<span style="color:#c3e88d">${match}</span>`);
        }
        return `__TOKEN_${i}__`;
    });

    // 2. Highlight keywords and numbers
    esc = esc
        .replace(/\b(const|let|var|import|export|from|async|await|function|return|if|for|of|in|new|type|interface|extends|implements|default|class|switch|case|break|throw|try|catch)\b/g, '<span style="color:#c792ea">$1</span>')
        .replace(/\b(\d+)\b/g, '<span style="color:#f78c6c">$1</span>');

    // 3. Restore tokens
    return esc.replace(/__TOKEN_(\d+)__/g, (match, i) => tokens[i]);
}

// ── Component ────────────────────────────────────────────────────────
export default function App() {
    const [activeCat, setActiveCat] = useState("All");
    const [search, setSearch] = useState("");
    const [selected, setSelected] = useState(null);
    const [copied, setCopied] = useState(false);

    const filtered = useMemo(() => {
        return FEATURES.filter(f => {
            const matchCat = activeCat === "All" || f.cat === activeCat;
            const q = search.toLowerCase();
            const matchSearch = !q || f.title.toLowerCase().includes(q) || f.cat.toLowerCase().includes(q) || f.tip.toLowerCase().includes(q) || f.code.toLowerCase().includes(q);
            return matchCat && matchSearch;
        });
    }, [activeCat, search]);

    const catCounts = useMemo(() => {
        const c = {};
        FEATURES.forEach(f => { c[f.cat] = (c[f.cat] || 0) + 1; });
        return c;
    }, []);

    const selectedIdx = selected ? filtered.findIndex(f => f.id === selected.id) : -1;

    function copy() {
        if (!selected) return;
        navigator.clipboard?.writeText(selected.code);
        setCopied(true);
        setTimeout(() => setCopied(false), 1500);
    }

    return (
        <div style={{ display: "flex", height: "100vh", fontFamily: "'DM Mono',monospace", background: "#faf9f6", overflow: "hidden" }}>
            {/* Sidebar */}
            <div style={{ width: 252, minWidth: 252, background: "#fff", borderRight: "1px solid #e8e5de", display: "flex", flexDirection: "column", overflow: "hidden" }}>
                <div style={{ padding: "18px 16px 14px", borderBottom: "1px solid #e8e5de" }}>
                    <div style={{ fontFamily: "Georgia,serif", fontSize: 17, fontWeight: 600, color: "#0f0e0b", lineHeight: 1.25 }}>Contentful<br />Reference</div>
                    <div style={{ display: "inline-block", marginTop: 6, background: "#e8521a", color: "#fff", fontSize: 10, fontWeight: 500, padding: "2px 8px", borderRadius: 20, letterSpacing: "0.5px" }}>200 FEATURES</div>
                </div>
                <div style={{ padding: "10px 12px", borderBottom: "1px solid #e8e5de" }}>
                    <input
                        value={search}
                        onChange={e => setSearch(e.target.value)}
                        placeholder="Search features…"
                        style={{ width: "100%", background: "#faf9f6", border: "1px solid #e8e5de", borderRadius: 6, padding: "6px 10px", fontFamily: "'DM Mono',monospace", fontSize: 11.5, color: "#0f0e0b", outline: "none", boxSizing: "border-box" }}
                    />
                </div>
                <div style={{ overflowY: "auto", flex: 1, padding: "6px 0" }}>
                    {["All", ...CATEGORIES].map(cat => {
                        const isActive = activeCat === cat;
                        const count = cat === "All" ? FEATURES.length : catCounts[cat] || 0;
                        return (
                            <button key={cat} onClick={() => setActiveCat(cat)} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", width: "100%", padding: "7px 16px", background: "none", border: "none", borderLeft: isActive ? `3px solid ${CAT_COLORS[cat] || "#e8521a"}` : "3px solid transparent", cursor: "pointer", fontFamily: "'DM Mono',monospace", fontSize: 11, color: isActive ? (CAT_COLORS[cat] || "#e8521a") : "#4a4740", textAlign: "left", fontWeight: isActive ? 500 : 400 }}>
                                <span>{cat}</span>
                                <span style={{ fontSize: 10, background: isActive ? (CAT_COLORS[cat] || "#e8521a") : "#f0ede6", color: isActive ? "#fff" : "#8a8680", padding: "1px 6px", borderRadius: 10 }}>{count}</span>
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* Main grid */}
            <div style={{ flex: 1, overflowY: "auto" }}>
                <div style={{ position: "sticky", top: 0, zIndex: 10, background: "#faf9f6", borderBottom: "1px solid #e8e5de", padding: "14px 24px", display: "flex", alignItems: "center", gap: 12 }}>
                    <div style={{ fontFamily: "Georgia,serif", fontSize: 20, fontWeight: 600, color: "#0f0e0b", letterSpacing: "-0.4px" }}>{activeCat === "All" ? "All Features" : activeCat}</div>
                    <div style={{ fontSize: 11, color: "#8a8680", background: "#fff", border: "1px solid #e8e5de", padding: "2px 10px", borderRadius: 20 }}>{filtered.length} features</div>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 1, background: "#e8e5de" }}>
                    {filtered.length === 0 && (
                        <div style={{ gridColumn: "1/-1", padding: 60, textAlign: "center", color: "#8a8680", background: "#faf9f6", fontSize: 13 }}>No features match your search.</div>
                    )}
                    {filtered.map(f => {
                        const col = CAT_COLORS[f.cat] || "#e8521a";
                        return (
                            <div key={f.id} onClick={() => setSelected(f)} style={{ background: "#fff", padding: "18px 20px", cursor: "pointer", transition: "background 0.1s" }}
                                onMouseEnter={e => e.currentTarget.style.background = "#f5f3ee"}
                                onMouseLeave={e => e.currentTarget.style.background = "#fff"}>
                                <div style={{ fontSize: 10, color: "#8a8680", marginBottom: 4, fontWeight: 500, letterSpacing: "0.5px" }}>#{String(f.id).padStart(3, "0")}</div>
                                <div style={{ fontFamily: "Georgia,serif", fontSize: 14.5, fontWeight: 600, color: "#0f0e0b", marginBottom: 5, lineHeight: 1.3 }}>{f.title}</div>
                                <div style={{ fontSize: 11, color: "#6a6660", lineHeight: 1.5, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{f.tip}</div>
                                <div style={{ display: "inline-block", marginTop: 8, fontSize: 9, fontWeight: 500, padding: "2px 7px", borderRadius: 10, background: `${col}18`, color: col, border: `1px solid ${col}40`, letterSpacing: "0.3px" }}>{f.cat}</div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Modal */}
            {selected && (
                <div onClick={e => { if (e.target === e.currentTarget) setSelected(null); }} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)", zIndex: 100, display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
                    <div style={{ background: "#fff", borderRadius: 12, border: "1px solid #e8e5de", width: "100%", maxWidth: 740, maxHeight: "88vh", overflowY: "auto" }}>
                        <div style={{ padding: "20px 24px 16px", borderBottom: "1px solid #e8e5de", position: "sticky", top: 0, background: "#fff", zIndex: 1 }}>
                            <div style={{ fontSize: 10, color: "#8a8680", letterSpacing: "0.5px", marginBottom: 4, fontWeight: 500 }}>#{String(selected.id).padStart(3, "0")} · {selected.cat}</div>
                            <div style={{ fontFamily: "Georgia,serif", fontSize: 22, fontWeight: 600, color: "#0f0e0b", letterSpacing: "-0.4px", paddingRight: 36 }}>{selected.title}</div>
                            <button onClick={() => setSelected(null)} style={{ position: "absolute", right: 20, top: 18, background: "#faf9f6", border: "1px solid #e8e5de", width: 28, height: 28, borderRadius: "50%", cursor: "pointer", fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center", color: "#4a4740" }}>✕</button>
                        </div>
                        <div style={{ padding: "20px 24px" }}>
                            <div style={{ background: "#fff8e6", border: "1px solid #f0c040", borderRadius: 8, padding: "12px 14px", marginBottom: 16, fontSize: 12, color: "#5a4a00", lineHeight: 1.6 }}>
                                <strong style={{ color: "#3a3000" }}>💡 Tip: </strong>{selected.tip}
                            </div>
                            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                                <span style={{ fontSize: 11, color: "#8a8680" }}>Code example</span>
                                <button onClick={copy} style={{ fontFamily: "'DM Mono',monospace", fontSize: 11, background: "#faf9f6", border: "1px solid #e8e5de", padding: "4px 12px", borderRadius: 5, cursor: "pointer", color: "#4a4740" }}>{copied ? "Copied!" : "Copy"}</button>
                            </div>
                            <pre style={{ background: "#0f0e0b", color: "#e8e5de", borderRadius: 8, padding: "16px", overflowX: "auto", fontSize: 12, lineHeight: 1.75, fontFamily: "'DM Mono',monospace", margin: 0 }}>
                                <code dangerouslySetInnerHTML={{ __html: hlCode(selected.code) }} />
                            </pre>
                        </div>
                        <div style={{ display: "flex", gap: 8, padding: "14px 24px", borderTop: "1px solid #e8e5de" }}>
                            <button disabled={selectedIdx <= 0} onClick={() => setSelected(filtered[selectedIdx - 1])} style={{ fontFamily: "'DM Mono',monospace", fontSize: 11, background: "#faf9f6", border: "1px solid #e8e5de", padding: "6px 14px", borderRadius: 6, cursor: selectedIdx <= 0 ? "not-allowed" : "pointer", color: "#4a4740", opacity: selectedIdx <= 0 ? 0.4 : 1 }}>← Prev</button>
                            <button disabled={selectedIdx >= filtered.length - 1} onClick={() => setSelected(filtered[selectedIdx + 1])} style={{ fontFamily: "'DM Mono',monospace", fontSize: 11, background: "#faf9f6", border: "1px solid #e8e5de", padding: "6px 14px", borderRadius: 6, cursor: selectedIdx >= filtered.length - 1 ? "not-allowed" : "pointer", color: "#4a4740", opacity: selectedIdx >= filtered.length - 1 ? 0.4 : 1 }}>Next →</button>
                            <span style={{ marginLeft: "auto", fontSize: 11, color: "#8a8680", alignSelf: "center" }}>{selectedIdx + 1} / {filtered.length}</span>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}